INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('_RJbVN6pdtaI', 'Genetik in 30 Sekunden', 'Jonathan Weitzman; Matthew Weitzman', 2024, 'Science', 'science', 'German', '9789089988812', 'Librero', 160, 4.7, 8, NULL, NULL, '… in 30 Sekunden', NULL, NULL, 'https://www.amazon.de/dp/1782405475', 'https://m.media-amazon.com/images/I/91rDCTYt1hL.jpg', 'Was ist die DNA und inwieweit bestimmen unsere Gene, wer wir sind? Wie wirkt eine Gentherapie? In den letzten hundert Jahren erlebte die Genetik atemberaubende Fortschritte. In diesem gut verständlichen Handbuch erfahren Sie alles Wesentliche zum Thema – von den Grundlagen bis aktuellen Forschungsergebnissen. Genetik in 30 Sekunden bricht den Fachjargon auf und berichtet von den Meilensteinen der Genetik, begonnen bei den Grundlagen der Zellbiologie bis zu den schier unglaublichen Entwicklungen in der DNA-Sequenzierung und der Genomchirurgie. Fortschritte bei der Stammzellentherapie, beim Klonen von Tieren, maßgeschneiderte Gentherapie und gentechnisch verändertes Getreide haben für Schlagzeilen gesorgt. Haben Sie sich je darüber Gedanken gemacht, was unter all dem zu verstehen ist und was das für unsere Zukunft bedeutet? Experten knacken in 50 Kapiteln den Code und entschlüsseln so die zentralen Begriffe und Ideen zur Genetik auf je einer Doppelseite in Wort und Bild. Dank der informativen Glossare, anschaulichen Grafiken und Biografien der wichtigsten Forscher werden Sie sich schon bald in diesem zentralen Wissenschaftsgebiet der Zukunft zu Hause fühlen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('tC_qd23AduIY', 'Swiss Made', 'R. James Breiding', 2012, 'Non-fiction', 'non-fiction', 'English', '9781898948202', 'Profile Books', 432, 3.94, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.com/dp/1898948201', 'https://covers.openlibrary.org/b/id/15195961-L.jpg', 'Eine umfassende Erkundung des wirtschaftlichen Erfolgs der Schweiz: "Swiss Made" von R. James Breiding beleuchtet die Faktoren, die zum weltweiten Ruf des Landes für Innovation, Stabilität und Wohlstand beitragen. Das Buch untersucht eine Vielzahl von Branchen – von Finanzen und Pharmazeutik bis hin zu Technologie und Uhrmacherei – und hebt die kulturellen und historischen Einflüsse hervor, die Schweizer Geschäftsumfeld so einzigartig geprägt haben.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:36:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('DJHRCgRo04-T', 'Der Crash kommt', 'Max Otte', 2019, 'Economics', 'finance', 'German', '9783426306253', 'Droemer Taschenbuch', 432, 3.8, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/3426306254', 'https://exlibris.azureedge.net/covers/9783/4263/0625/3/9783426306253xxl.webp', 'Eine Analyse wirtschaftlicher Entwicklungen und eine Warnung vor einer drohenden Finanzkrise: "Der Crash kommt" von Max Otte nimmt die wirtschaftlichen Herausforderungen und Verwerfungen vorweg, die zu einem gravierenden Markteinbruch führen könnten.', 'claude-translated-de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-14 13:36:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('cjiXHYQF4K1Q', 'Crashkurs – Dirk Müller', 'Dirk Müller', 2006, 'Economics', 'finance', 'German', '978-3938350149', 'Droemer Knaur', 349, 4.4, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/3938350140', 'https://images-na.ssl-images-amazon.com/images/P/3938350148.01.LZZZZZZZ.jpg', 'Eine kurzweilige Erkundung der globalen Finanzmärkte: "Crashkurs" von Dirk Müller macht komplexe wirtschaftliche Zusammenhänge für den Leser verständlich. Das 2009 erschienene Buch beleuchtet die Ursachen und Folgen der Finanzkrise und führt den Leser mit praktischen Ratschlägen und Lösungsansätzen durch wirtschaftliche Theorien. Bekannt für seinen klaren und zugänglichen Stil, bietet Müller eine einzigartige Perspektive aus seiner langjährigen Erfahrung im Finanzbereich.', 'claude-translated-de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-14 13:36:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('raSRTUkjjLrZ', 'Six Sigma für Dummies', 'Craig Gygi / Bruce Williams / Neil DeCarlo', 2006, 'Non-fiction', 'non-fiction', 'English', '978-0470045190', 'For Dummies', 318, 4.4, 107, NULL, '1.', '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/0470045191', 'https://m.media-amazon.com/images/I/71kWWG+fenL.jpg', 'Steigern Sie Ihre Effizienz – und erzielen Sie satte Gewinne! Benötigen Sie Hilfe bei der Einführung oder beim Verständnis von Six Sigma? Möchten Sie diese leistungsstarke Problemlösungsmethodik auf Ihr Unternehmen anwenden? Six Sigma ist längst nicht mehr nur großen Konzernen vorbehalten – es eignet sich für jedes Unternehmen, auch Ihres, ganz gleich wie groß oder klein. Dieses praxisorientierte Arbeitsbuch vermittelt Ihnen das Wissen, die Einblicke und die praktischen Übungen, die Sie benötigen, um Six Sigma zu beherrschen und in Ihrem Unternehmen einzusetzen. Als ideale Begleitung zu "Six Sigma für Dummies" – oder jedem anderen Six Sigma-Buch – bietet Ihnen dieses Übungsbuch eine Fülle von Beispielen, Aufgaben und weiteren Werkzeugen, um Six Sigma-Theorie ab sofort in die Praxis umzusetzen. Entdecken Sie: Wie Sie eine Six Sigma-Initiative aufbauen und leiten • Projektausrichtung an Unternehmenszielen und -strategie • Wie Sie Prozessablaufkarten und -modelle erstellen • Diagramm- und Graphendarstellung für Analyse und Auswertung • Methoden zur Berechnung von Sigma-Werten • Wie Sie Variablenbeziehungen quantifizieren', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:36:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('E5uENuxFdwOr', 'Statistik mit Excel für Dummies', 'Joseph Schmuller', 2017, 'Non-Fiction', 'non-fiction', 'German', '978-3527713643', 'Wiley-VCH', 468, 4.8, 16, NULL, '7.', '… für Dummies', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/51X-Aoo-BHL.jpg', 'Java für Dummies ist gleichzeitig ein Lehrbuch und ein unverzichtbares Nachschlagewerk für alle Java-Programmierer. Basiswissen zur objektorientierten Programmierung wird genauso vermittelt wie das Prinzip der Wiederverwendbarkeit von Programmbausteinen und allgemeine Grundlagen der Java-Programmierung. Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('DOU7tony9Fgo', 'Übungsbuch Statistik für Dummies', 'Deborah J. Rumsey', 2016, 'Non-Fiction', 'non-fiction', 'German', '3527707071', 'Wiley-VCH', 368, 4.5, NULL, NULL, NULL, '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527707071', 'https://covers.openlibrary.org/b/id/14671956-L.jpg', 'Ein praxisorientierter Leitfaden für Studierende und Berufstätige, der verständliche Erklärungen und Übungen bietet, um statistische Konzepte sicher zu beherrschen.', 'claude-translated-de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 13:36:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ocTmmscYYc87', 'Statistik für Dummies', 'Deborah J. Rumsey', 2014, 'Non-fiction', 'non-fiction', 'German', '978-3-527-71018-1', 'Wiley-VCH', 292, 4.4, 296, NULL, '1.', '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527710182', 'https://m.media-amazon.com/images/I/610vByMhHWL.jpg', 'Wollen Sie wissen, was mit Ihrem Geld gemacht wird? Dann sind Aktien für Sie die richtige Wahl, denn Sie haben es als Mitunternehmer in der Hand, wem Sie Ihr Geld anvertrauen. Doch was ist eigentlich das Grundprinzip von Aktien? Welche Vorteile haben sie gegenüber anderen Anlageformen? Wie kommen Sie an Aktien und wie ordern Sie geschickt, um Chancen zu nutzenund Risiken überschaubar zu halten? Was beeinflusst Kurse und wie analysieren Sie Kursverläufe, um den richtigen Zeitpunkt für Kauf und Verkauf abzupassen? Wie können Sie mit ganz einfachen Mitteln, Ihre eigene Anlagestrategie entwickeln? Diese und viele weitere Fragen rund um Aktien, Kursverläufe und Börsenpsychologie beantworten Ihnen die beiden Aktienexperten Dr. Christine Bortenlänger und Ulrich Kirstein in diesem Buch, das für die Shortlist des deutschen Finanzbuchpreises nominiert wurde. Damit auch Sie schon bald von Kursen und Dividenden profitieren! Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fh8gVaj1Wcxo', 'Logik für Dummies', 'Mark Zegarelli', 2016, 'Non-Fiction', 'non-fiction', 'German', '9783527711031', 'Wiley-VCH', 360, 4.2, 51, NULL, '1.', '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527711030', 'https://m.media-amazon.com/images/I/61-8hmewJmL.jpg', 'Logik ist die Basis der Wissenschaft, aber auch eine Brücke zwischen Wissenschaft und Alltag, denn die Grundlagen sind einfach logisch. Doch so einfach sie auf den ersten Blick scheint, so anspruchsvoll ist sie im Detail. "Logik kompakt für Dummies" führt Sie systematisch und so einfach wie möglich in dieses Teilgebiet von Mathematik und Philosophie ein. Dabei arbeitet Mark Zegarelli mit anschaulichen Beispielen und schafft es so, dieses abstrakte Thema nicht nur verständlich zu erklären, sondern auch Wert und Nutzen der Logik aufzuzeigen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('vT4kARjSbiAc', 'XML für Dummies', 'Lucinda Dykes / Ed Tittel', 2003, 'Non-fiction', 'non-fiction', 'German', '978-3-527-70129-0', 'Wiley-VCH', 304, 4.6, 12, NULL, '1.,', '… für Dummies', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/51VkA3-tD+L.jpg', 'Schlagzeug und Percussionsinstrumente gelten als leichter Einstieg in die Musik. Doch viele Anfänger stehen schon sehr bald vor dem Problem, die vielfältigen Möglichkeiten des Schlagzeugs zu meistern. Jeff Strong zeigt dem Leser, welche Instrumente zu einem Schlagzeug gehören und welche als Percussionsinstrumente eingesetzt werden. Vom einfachen Rhythmus bis zur lateinamerikanischen Musik, Jazz, Blues und Funk erfährt der Einsteiger alles Grundlegende zu Beats und Tempi. Mehr lesen', 'amazon_de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('klOfBdC281sw', 'Zeitmanagement für Dummies', 'Dirk Mayer', 2007, 'Self-help', 'self-help', 'German', '978-3527519303', 'Wiley-VCH', 352, 4.5, NULL, NULL, NULL, '… für Dummies', NULL, NULL, 'https://www.amazon.de/dp/3527519304', 'https://covers.openlibrary.org/b/id/2216020-L.jpg', NULL, 'pax-audit-openlibrary', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_6bc7a4389671', 'Wahrscheinlichkeitsrechnung für Dummies', 'Deborah Rumsey', 2007, 'Nonfiction', 'non-fiction', 'German', '978-3-527-70351-7', 'Wiley-VCH Verlag GmbH & Co. KGaA', 452, 3.9, 8, NULL, '1. Auflage', '… für Dummies', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/61hrecHTNDL.jpg', 'Beim Thema Rechtschreibung zucken viele zusammen. Schon in der Schule waren den meisten Diktate ein Graus. Groß- oder kleinschreiben, auseinander oder zusammen, und wo überhaupt muss ein Komma stehen oder ein Bindestrich? Peinlich, wenn dann später das Bewerbungsschreiben vor Fehlern nur so strotzt, die Examensarbeit inhaltlich zwar top, in Sachen Orthografie aber ein Flop ist oder in der Geschäftskorrespondenz mit wichtigen Kunden unzählige Kommafehler stecken. Ebenfalls unschön, wenn Newsletter und Flyer mehr durch ihre mangelhafte Rechtschreibung als durch ihren Inhalt auffallen. Hinzu kommt die Gewissheit, dass auf das Korrekturprogramm des PC auch kein Verlass ist. Und obendrein noch das Hin und Her um die Rechtschreibung in den letzten Jahren. Wer weiß da überhaupt noch, was Sache ist? Sich auf der Suche nach dem Neuen durch das amtliche Regelwerk zu wühlen, ist ein mühsames Geschäft. Das muss auch gar nicht sein. Dr. Matthias Wermke, der Leiter der Dudenredaktion, verbindet in "Neue deutsche Rechtschreibung für Dummies" die Kompetenz des Dudens mit dem lockeren Stil der Dummies, der Berührungsängste vor trockenen Themen nimmt. Und auf einmal werden die Regeln der neuen deutschen Rechtschreibung sogar Orthografiemuffeln verständlich. Als besonderes Extra enthält der Band ein Wörterbuch mit 47.000 Stichwörtern. Mehr lesen', 'amazon_de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_24509925f484', 'Mathe in 30 Sekunden', 'Richard J. Brown', 2012, 'Mathematics', 'science', 'German', '978-3-8310-2185-4', 'Dodax AG', 328, 3.59, NULL, NULL, NULL, '… in 30 Sekunden', NULL, NULL, 'https://www.dodax.de/de-de/buecher-hoerbuecher/mathematik/mathe-in-30-sekunden-richard-j-brown-dpI1Q50O9360/', 'https://images-na.ssl-images-amazon.com/images/P/3831021856.01.LZZZZZZZ.jpg', '"Mathe in 30 Sekunden" von Richard J. Brown ist eine kompakte Erkundung zentraler mathematischer Konzepte, die darauf ausgelegt ist, komplexe Ideen in kurzen, leicht verständlichen Abschnitten zu erläutern. Jedes Thema soll in 30 Sekunden erfassbar sein, was das Buch zu einer zugänglichen Ressource für alle macht, die sich für die Grundlagen der Mathematik interessieren. Das Buch deckt ein breites Themenspektrum ab – von der Geometrie bis zur Analysis – und bietet eine anschauliche Zusammenfassung wesentlicher mathematischer Prinzipien.', 'claude-translated-de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 13:36:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_2971171ded6f', 'Newton in 30 Sekunden', 'Brian Clegg', 2016, 'Science', 'science', 'German', '9789089987488', 'Librero', 160, 4.4, 12, NULL, NULL, '… in 30 Sekunden', NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/614ooUnZWyL.jpg', 'Die Geschichte vom Apfel, der ihm auf den Kopf fiel, ist weltberühmt, aber was wissen Sie noch über Isaac Newton? Er war ein Multitalent – Physiker, Astronom, Alchemist und Mathematiker –, und die Genialität seines Werkes bahnte zahllosen wissenschaftlichen Entdeckungen den Weg. Frischen Sie Ihre Kenntnisse über sein beeindruckendes Erbe auf und lesen Sie Interessantes über ein Genie, das unsere Welt mitgeformt hat. Newton in 30 Sekunden vermittelt ein einzigartiges Bild eines der größten Genies aller Zeiten und präsentiert seine wichtigsten Ideen und Theorien. Jede Buchseite steckt voller Informationen: von seinen Entdeckungen zu Schwerkraft, Licht, Farben sowie Differential- und Integralrechnung bis zu seiner Zeit als Mitglied des Parlaments. Brian Clegg, Herausgeber, studierte Naturwissenschaften mit Schwerpunkt Experimentalphysik an der Universität Cambridge. Er schrieb für verschiedene Zeitschriften und Zeitungen wie Nature, The Times und The Wall Street Journal und unterrichtete an den Universitäten Oxford und Cambridge sowie der Royal Institution. Er ist Redakteur bei www.popularscience.co.uk und Verfasser zahlreicher Bücher, darunter Quantentheorie in 30 Sekunden. Mehr lesen', 'amazon_de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_b7c33e0b423d', 'Einstein in 30 Sekunden', 'Brian Clegg', 2017, 'Science', 'science', 'German', '9789089988799', 'Librero', 160, 4.1, 14, NULL, NULL, '… in 30 Sekunden', NULL, NULL, 'https://www.amazon.com/dp/1848312627', 'https://m.media-amazon.com/images/I/91y3kqxuwlL.jpg', 'Albert Einstein war ein bahnbrechendes Genie, dessen Ideen und Theorien die Wissenschaft revolutionierten. Mehr als einmal stellte er die Wahrnehmung des Universums auf den Kopf. Mit gerade einmal 26 Jahren sorgte der spätere Nobelpreisträger für wissenschaftlich spektakuläre Erkenntnisse. Albert Einstein war nicht nur ein herausragender Physiker, sondern außerdem ein Kämpfer für die Menschenrechte und ein politischer Aktivist. Einstein, der die wohl berühmteste Formel der modernen Physik E=mc2 formulierte, gilt bis heute als Prototyp des verschrobenen Professors. Einstein in 30 Sekunden eröffnet Ihnen die Gedankenwelt des wohl berühmtesten Physikers unserer Zeit, dessen außergewöhnliches Leben in gleichem Maße wie seine wissenschaftlichen Leistungen beeindruckt. Mit jedem der 50 informativen Kapitel werden sie Albert Einsteins Werk, Leben und Erbe besser verstehen – von der Relativitätstheorie über die Quantenphysik bis zur Kernspaltung. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_ce9e5dcf9490', 'Mythologie in 30 Sekunden', 'Robert A. Segal', 2024, 'Mythology', 'mythology', 'German', '9789089985958', 'Librero', 160, 4.7, 24, NULL, 'New', '… in 30 Sekunden', NULL, NULL, 'https://www.amazon.de/dp/9089985957', 'https://m.media-amazon.com/images/I/81fVIseZnZL.jpg', 'Mythologie in 30 Sekunden beleuchtet die wichtigsten Inhalte der bekanntesten klassischen Mythen und erklärt deren verborgene Bedeutung. Das Buch behandelt den Ursprung von Göttern, Helden und Dämonen der alten Griechen und Römer und erläutert dem Leser die grundlegenden Aspekte ihrer Überlieferungen in einer halben Minute auf jeweils zwei Seiten, in rund dreihundert Wörtern und anhand einer Abbildung. Mythologie in 30 Sekunden enthält die Biografien der sieben größten Dichter und Dramatiker des Altertums und verdeutlicht kurz und prägnant den bleibenden Einfluss antiker Mythen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 08:23:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_096439cc1d72', 'GRU – Die Speerspitze', 'Viktor Suworow', 2002, 'Non-fiction', 'non-fiction', 'German', '9783423205166', 'Goldmann', 329, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/3423205161', 'https://images-na.ssl-images-amazon.com/images/P/3423205164.01.LZZZZZZZ.jpg', 'Eigentlich hat sich Kommissar Laurenti auf eigenen ruhigen Triester Sommer eingestellt. Doch nach einem merkwürdigen Yacht-Unfall bekommt er es mit Mord, Geldwäsche und Menschenschmuggel zu tun. Darunter leidet nicht nur sein Familienleben ...', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:57:38');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_42ee89dbef0f', 'Kampf der Kulturen', 'Samuel P. Huntington', 2006, 'Political Science', 'political-science', 'German', '978-3492048461', 'Simon & Schuster; Rowohlt Taschenbuch Verlag', 536, 4.2, NULL, NULL, NULL, NULL, NULL, '["Berlin (Germany)"]', NULL, 'https://covers.openlibrary.org/b/id/1007600-L.jpg', 'Ein einflussreiches Werk der Politikwissenschaft, das die Theorie kultureller Konflikte untersucht, die die Weltpolitik nach dem Ende des Kalten Krieges prägen. Im Mittelpunkt steht die These, dass künftige Kriege nicht zwischen Staaten, sondern zwischen Kulturen ausgetragen werden.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:36:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_0cc2817c4d8f', 'Taktik gegen Terror', 'Gayle Rivers', 1987, 'Non-fiction', 'non-fiction', 'German', '9783280017579', 'Orell Füssli Verlag', 216, 4.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/61kE1D5o7uL.jpg', 'Rivers, Gayle: Taktik gegen den Terror. Zürich, Wiesbaden. Orell Füssli 1987. Gr-8vo. 213 S. OPb. mit OSchU. Umschlag berieben, druckspurig, leicht bestoßen und stockfleckig, Einband bestoßen, Schnitt (stock-)fleckig, Notiz auf Titel, Seitenkanten altersgemäß gebräunt, sonst in gutem Zustand. Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:08:30');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_0db9e7c3007f', 'US Rangers', 'David Schauer', 1986, 'Military History', 'history', 'English', '9783613011366', 'Motorbuch', 205, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783613011366&printsec=frontcover&img=1&zoom=3', 'Eine umfassende Darstellung der Geschichte und der Einsätze der US Rangers, die ihre Entwicklung, bedeutende Missionen und ihren Einfluss auf militärische Taktiken im Detail beleuchtet – verfasst von David Schauer.', 'claude-translated-de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 13:36:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_e4f4f2d38a43', 'Soldaten aus dem Dunkel', 'Carl Jacobi', NULL, 'Horror', 'horror', 'German', NULL, 'Arkham House', 208, 4.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Eine schaurige Horrorgeschichte von Carl Jacobi: "Soldaten aus dem Dunkel" spinnt ein Netz aus Spannung und übernatürlichen Begegnungen und zieht den Leser in eine Welt, in der die Finsternis böswillige Mächte verbirgt.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:36:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_9f184abdafad', 'NSA – Amerikas geheimster Nachrichtendienst', 'James Bamford', 1983, 'Non-fiction', 'non-fiction', 'German', '9780140067484', 'Penguin Books', 655, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9780/1400/6748/4/9780140067484xxl.webp', 'Eine eingehende Betrachtung der National Security Agency (NSA), die deren geheime Operationen, Geschichte und Einfluss auf die weltweite Nachrichtendienstarbeit beleuchtet.', 'claude-translated-de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 13:36:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('syn_82cfc37b6a9c', 'Reagan und die geheimen Kriege der CIA', 'Bob Woodward', 1987, 'Non-fiction', 'non-fiction', 'German', '9783426263402', 'Droemer Knaur', 447, 3.88, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.de/dp/9783548357434', 'https://books.google.com/books?vid=ISBN9783426263402&printsec=frontcover&img=1&zoom=3', 'Ein investigativer Bericht von Bob Woodward, der geheime CIA-Operationen während der Präsidentschaft Ronald Reagans beleuchtet und die Komplexitäten sowie Kontroversen der amerikanischen Geheimdienstaktivitäten in den 1980er Jahren untersucht.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('bb0yOaScc7EE', 'Geheime Nachrichten-Technik', 'Otto Schreier', 1996, 'Military', 'history', 'English', '978-3-540-60605-6', 'Springer', 300, NULL, NULL, NULL, NULL, NULL, NULL, '["Science"]', NULL, 'https://images-na.ssl-images-amazon.com/images/P/354060605X.01.LZZZZZZZ.jpg', 'Dieser Band erscheint zu Ehren des 100. Geburtstags von Friedrich Hund. Er bietet einen modernen Überblick über Materie bei hohen Dichten und Drücken in der Astrophysik – von Hunds frühen Beiträgen bis hin zu heutigen Konzepten. Der Zusammenhang zwischen der Zustandsgleichung und der Struktur kompakter kosmischer Objekte wird erörtert; zwei zentrale Beiträge behandeln die Zustandsgleichung baryonischer Materie bei nuklearen Dichten sowie die numerische Lösung der allgemein-relativistischen Feldgleichungen für nicht rotierende und schnell rotierende Neutronensterne. In einem abschließenden Kapitel wird der aktuelle Stand der Asteroseismologie als Werkzeug zur Erforschung des Inneren kosmischer Objekte vorgestellt, indem beobachtete freie Schwingungen der Erde, der Sonne und weißer Zwergsterne analysiert werden.', 'claude-translated-de', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fOcjD2CZC5jp', 'Nuclear Battlefields', 'William M. Arkin; Richard W. Fieldhouse', 1985, 'Non-fiction', 'non-fiction', 'English', '0871568530', 'Ballinger Publishing Company', 477, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://www.amazon.com/dp/0871568530', 'https://covers.openlibrary.org/b/id/6639865-L.jpg', 'Eine eingehende Untersuchung der weltweiten nuklearen Waffeninfrastruktur während des Kalten Krieges, die Standorte, Strategien und Auswirkungen nuklearer Arsenale und Schlachtfelder rund um den Globus beleuchtet.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('IB83F_KcAMLt', 'Credit Risk Modeling using Excel and VBA', 'Gunter Löffler; Peter N. Posch', 2010, 'Finance', 'finance', 'English', '9780470660928', 'Wiley', 368, 4.1, 51, NULL, '2.', NULL, NULL, '["Business & Economics"]', 'https://www.wiley.com/en-us/Credit+Risk+Modeling+using+Excel+and+VBA-p-9780470660928', 'https://m.media-amazon.com/images/I/718xMKcSdcL.jpg', 'Es ist weit verbreitet, die Unzulänglichkeit von Kreditrisikomodellen dafür verantwortlich zu machen, dass die Finanzkrise viele Marktteilnehmer unvorbereitet traf. Bei näherer Betrachtung zeigt sich jedoch häufig, dass die Marktteilnehmer die Modelle nicht richtig verstanden oder angewendet haben. Die jüngsten Ereignisse stellen daher die traditionelle Kreditrisikomodellierung, wie sie in der ersten Auflage des Buches beschrieben wurde, nicht grundsätzlich in Frage. Eine zweite Auflage ist dennoch zeitgemäß, da die erste Auflage jene Instrumente, die in der Krise eine zentrale Rolle spielten (CDS und CDO), nur kurz behandelte. Neben einer ausführlicheren Darstellung dieser Instrumente konzentriert sich das Buch auf Modellierungsaspekte, die in der Finanzkrise besonders relevant waren (z. B. Schätzfehler), und veranschaulicht den Nutzen der Kreditrisikomodellierung anhand von Fallstudien. Dieses Buch bietet Praktikern und Studierenden eine anschauliche, praxisorientierte Einführung in die moderne Kreditrisikomodellierung. Jedes Kapitel beginnt mit einer Erläuterung der Methodik, bevor die Autoren den Leser Schritt für Schritt durch die Umsetzung der Verfahren in Excel und VBA führen. Der Schwerpunkt liegt auf Fragen des Risikomanagements; behandelt werden die Schätzung von Ausfallwahrscheinlichkeiten (Scoring, Strukturmodelle und Übergangsmatrizen), Korrelations- und Portfolioanalyse, Validierung sowie Kreditausfallswaps und strukturierte Finanzierungen. Zum Buch gehört eine begleitende Website, https://creditriskmodeling.wordpress.com/, die eigens für diese zweite Auflage aktualisiert wurde und Folien sowie Übungsaufgaben für Dozenten enthält.', 'claude-translated-de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('xoKYLPLooJ1Y', 'Speed Reading', 'Tony Buzan', 1990, 'Non-fiction', 'non-fiction', 'English', '9780452266049', 'Penguin', 192, 4.2, 66, NULL, '3.', NULL, NULL, NULL, 'https://www.amazon.com/dp/0452266041', 'https://m.media-amazon.com/images/I/91SNW5KssmL.jpg', 'Vom Bestsellerautor von The Mind Map Book und Use Both Sides of Your Brain – steigern Sie Ihre Lesegeschwindigkeit, Ihr Textverständnis und Ihre Merkfähigkeit dramatisch. Tony Buzan, weltbekannter Experte auf dem Gebiet des Gehirns und Erfinder des Mind Mappings, hat mit den in Speed Reading vorgestellten Methoden internationale Anerkennung erlangt. Das Buch enthält nicht nur die bewährten Grundlagen des Schnelllesens, sondern ist das erste Werk zu diesem Thema, das die neuesten Erkenntnisse über das erstaunliche Potenzial und die komplexen Funktionsweisen des menschlichen Gehirns einbezieht. In einem leicht verständlichen, direkten Stil bietet dieser Klassiker: • Neue Ansätze zum Lesen, Lernen, zur Konzentration und Wissensaneignung • Selbsttests, die das Interesse an verschiedenen Wissensgebieten anregen • Die Möglichkeit, Ihre Lese- und Verständnisleistung zu messen und systematisch zu verbessern. Die überarbeitete dritte Auflage bietet modernste Techniken zur Steigerung von Lesegeschwindigkeit und Textverständnis – vom einfachsten bis zum anspruchsvollsten Niveau.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:37:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('rNCGaoOV0CWb', 'MasterClass: Tony Buzan', 'Tony Buzan', NULL, 'Non-Fiction', 'non-fiction', 'English', NULL, 'Watkins Publishing; Watkins Publishing Ltd.', NULL, 3.9, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://images-na.ssl-images-amazon.com/images/I/41Hx-4kdZ8L._SX362_BO1,204,203,200_.jpg', 'Ein umfassender Leitfaden von Tony Buzan zur Steigerung geistiger Fähigkeiten und zur Verbesserung von Lerntechniken, mit Schwerpunkt auf Gedächtnisverbesserung, schnellem Lesen und Mind-Mapping-Strategien.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('YdjbaGjCMQGj', 'Exchange Traded Funds und Anlagestrategien: Das ETF-Praxisbuch', 'Norbert Niedermayer; Christian Wagner', 2012, 'Finance/Investment', 'finance', 'German', '9783033033023', 'financialmedia AG', 419, 4.7, 5, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783033033023&printsec=frontcover&img=1&zoom=3', 'Exchange Traded Funds (ETFs) sind in den vergangenen Jahren zu einem wichtigen Baustein vieler Anlagedepots geworden. Dank breiter Risikodiversifikation, tiefen Kosten und einfacher Handelbarkeit werden sie nicht mehr nur von Privatanlegern eingesetzt. Auch professionelle Vermögensverwalter und institutionelle Anleger greifen vermehrt auf ETFs zurück. Aber wie funktionieren ETFs genau und welche Chancen und Risiken bieten sie? Welche Märkte decken sie ab? Auf was ist bei der ETF- bzw. Index-Wahl beim Investieren in Aktien, Anleihen, Rohstoffe, Hedge Funds usw. zu achten? Diese Themen sowie konkrete Einsatzmöglichkeiten von ETFs in Anlagestrategien und verschiedene Tipps bei der Umsetzung von Investitionsentscheidungen stehen im Mittelpunkt dieses Buches. Für das Verständnis von praktischen Herausforderungen bedarf es theoretischer Grundlagen. Auch diese kommen nicht zu kurz: Von der Theorie der Risikodiversifikation, den Optimierungsmethoden von Portfolios bis zu den Tücken des Tracking Errors. Die ausgewählten Themen sollen dem Leser eine kritische Auseinandersetzung mit häufig gestellten Fragen aus der Investmentwelt ermöglichen und Hilfestellung leisten. Nicht zu kurz kommen die Vorstellung der grössten ETF-Anbieter, Unterschiede zwischen den bekannten US-Aktienindizes wie S&P 500, Dow Jones und Nasdaq sowie viele weitere Fragestellungen aus der Praxis. Das Buch ist von Praktikern für Praktiker geschrieben und soll allen, die mehr rund um das Thema ETFs und Anlagestrategien wissen wollen, den Überblick erleichtern. Das vorliegende Buch eignet sich insbesondere für: Interessierte Privatanleger, Kundenberater, Portfoliomanager, Studenten und Journalisten. 28.06.2012 / NZZ: "Mit «Exchange Traded Funds und Anlagestrategien» geben Daniel Niedermayer und Marcel Wagner einen Leitfaden, um ETF zu verstehen und richtig einzusetzen." 20.06.2012 / FuW: "Ein neues, umfassendes Werk über Exchange Traded Funds liegt vor." Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:55:58');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('kxnAxRC41Buk', 'Managing Credit Risk (Second Edition)', 'John Caouette; Edward I. Altman; Paul Narayanan; Nimmo', 2008, 'Finance', 'finance', 'English', '9780470118726', 'Wiley', 656, 4.2, 7, NULL, '2.', NULL, NULL, NULL, 'https://www.wiley.com/en-us/Managing+Credit+Risk%2C+Second+Edition-p-9780470118720', 'https://m.media-amazon.com/images/I/71WeZIoT6vL.jpg', 'Managing Credit Risk, zweite Auflage, beginnt mit einer ausführlichen Erörterung der heutigen globalen Kreditmärkte – von der Bedeutung von Hedgefonds als wichtige Akteure bis hin zum wachsenden Einfluss von Ratingagenturen. Nach einem soliden Verständnis dieser Zusammenhänge werden einige der wirksamsten Instrumente, Techniken und Vehikel des Kreditrisikomanagements vorgestellt, die derzeit verfügbar sind. Wer mit den ständigen Veränderungen in der Welt des Kreditrisikomanagements Schritt halten muss, findet in diesem Buch die nötige Orientierung.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('kx6XOx0dNO9A', 'Introduction to Swiss Law', 'F. Dessemontet; T. Ansay', 1995, 'Legal', 'legal', 'English', '9789041153505', 'Kluwer Law International', 331, NULL, NULL, NULL, NULL, NULL, NULL, '["Law"]', 'https://www.amazon.com/dp/9041153506', 'https://covers.openlibrary.org/b/id/13239413-L.jpg', 'Ein umfassender Leitfaden zum Rechtssystem der Schweiz, der wesentliche Aspekte des schweizerischen Rechts für Studierende, Praktiker und alle behandelt, die das Rechtssystem des Landes verstehen möchten.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('CJoguOFxp7Ir', 'Das schweizerische Bankgeschäft', 'Urs Emch; Hugo Renz; Reto Arpagaus', 2011, 'Non-fiction', 'non-fiction', 'German', '9783725563241', 'Schulthess Juristische Medien', 1126, 5.0, NULL, NULL, '7.', NULL, NULL, NULL, 'https://www.amazon.de/dp/3039091739', 'https://books.google.com/books?vid=ISBN9783725563241&printsec=frontcover&img=1&zoom=3', 'Eine Darstellung des schweizerischen Bankwesens, die seine Geschichte, seinen Betrieb und seine Rolle im globalen Finanzmarkt beleuchtet.', 'claude-translated-de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('VMht1W7sF133', 'Operational Risk', 'Carol Alexander', 2003, 'Business & Economics', 'finance', 'English', '047084276X', 'FT Press; John Wiley & Sons', 392, 4.5, NULL, NULL, NULL, 'Market Risk Analysis', 3, NULL, 'https://www.amazon.com/dp/047084276X', 'https://covers.openlibrary.org/b/id/8702426-L.jpg', 'Ein umfassendes Werk, das die Herausforderungen und Rahmenbedingungen beim Management operationeller Risiken in Finanzinstituten untersucht, mit Schwerpunkt auf Messtechniken, regulatorischen Anforderungen und bewährten Verfahren zur Risikominderung.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:28:53');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('9tZ0Ed7kAv7r', 'Market Risk Analysis, Vol. I: Quantitative Methods in Finance', 'Carol Alexander', 2008, 'Finance', 'finance', 'English', '9780470998007', 'Wiley', 320, 4.7, 15, NULL, 'Volume I', 'Market Risk Analysis', 1, '["Business & Economics"]', 'https://www.amazon.com/dp/0470998009', 'https://m.media-amazon.com/images/I/61CaNiDaR0L.jpg', 'Verfasst von der führenden Wissenschaftlerin im Bereich Marktrisiko, Professorin Carol Alexander, ist Quantitative Methods in Finance der erste Band des vierbändigen Werks Market Risk Analysis. Von den Grundlagen ausgehend, hilft dieses Buch den Lesern, den ersten Schritt auf dem Weg zu einer fundierten Qualifikation als Finanzrisikomanager oder Vermögensverwalter zu machen – Berufsfelder, die derzeit stark nachgefragt werden. Das Buch richtet sich an aufgeschlossene Leser mit grundlegenden Mathematikkenntnissen auf Abiturniveau oder an Personen mit einem Hochschulabschluss in Mathematik, Physik oder Ingenieurwissenschaften; Vorkenntnisse in Finanzen sind nicht erforderlich. Der Schwerpunkt liegt auf dem Verständnis von Konzepten und nicht auf mathematischer Strenge, sodass das Buch einen schnellen Einstieg in die Finanzanalyse für Leser mit quantitativem Hintergrund bietet und dabei jene mathematischen Bereiche hervorhebt, die für die Lösung von Problemen im Finanz- und Vermögensrisikomanagement besonders relevant sind. Ein besonderes Merkmal dieses Buches ist die gleichzeitige Behandlung von zeitkontinuierlicher und zeitdiskreter Finanzmathematik: Quantitative Methods in Finance beschränkt sich damit nicht nur auf die Anwendung der Mathematik in der Finanzwelt, sondern erläutert in didaktisch vorbildlicher Weise, wie diese beiden Disziplinen zusammenwirken – ein umfassender, gut zugänglicher Leitfaden, der Lesern die Werkzeuge an die Hand gibt, ihr Wissen sofort anzuwenden. Der gesamte vierbändige Satz Market Risk Analysis veranschaulicht nahezu jeden Begriff und jede Formel anhand eines praktischen numerischen Beispiels oder einer ausführlicheren empirischen Fallstudie. Über alle vier Bände hinweg finden sich rund 300 numerische und empirische Beispiele, 400 Grafiken und Abbildungen sowie 30 Fallstudien, von denen viele in interaktiven Excel-Tabellen auf der beiliegenden CD-ROM enthalten sind. Empirische Beispiele und Fallstudien speziell für diesen Band umfassen: Hauptkomponentenanalyse europäischer Aktienindizes; Kalibrierung der Student-t-Verteilung mittels Maximum-Likelihood-Methode; Orthogonale Regression und Schätzung von Aktienfaktormodellen; Simulationen der geometrischen Brownschen Bewegung und korrelierter Student-t-Variablen; Bewertung europäischer und amerikanischer Optionen mit Binomialbäumen sowie europäischer Optionen mit der Black-Scholes-Merton-Formel; Kubische Spline-Anpassung von Zinskurven und impliziten Volatilitäten; Lösung des Markowitz-Problems ohne Leerverkäufe und mit weiteren Nebenbedingungen; Berechnung risikoadjustierter Performancekennzahlen, darunter das verallgemeinerte Sharpe-Verhältnis sowie Omega- und Kappa-Indizes.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:37:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('icxsCAz7jkI2', 'Market Risk Analysis, Vol. II: Practical Financial Econometrics', 'Carol Alexander', 2008, 'Finance/Economics', 'finance', 'English', '9780470998014', 'Wiley', 320, 4.7, 15, NULL, 'Volume I', 'Market Risk Analysis', 2, '["Business & Economics"]', NULL, 'https://images-na.ssl-images-amazon.com/images/P/0470998016.01.LZZZZZZZ.jpg', 'Verfasst von der führenden Wissenschaftlerin im Bereich Marktrisiko, Professorin Carol Alexander, ist Quantitative Methods in Finance der erste Band des vierbändigen Werks Market Risk Analysis. Von den Grundlagen ausgehend, hilft dieses Buch den Lesern, den ersten Schritt auf dem Weg zu einer fundierten Qualifikation als Finanzrisikomanager oder Vermögensverwalter zu machen – Berufsfelder, die derzeit stark nachgefragt werden. Das Buch richtet sich an aufgeschlossene Leser mit grundlegenden Mathematikkenntnissen auf Abiturniveau oder an Personen mit einem Hochschulabschluss in Mathematik, Physik oder Ingenieurwissenschaften; Vorkenntnisse in Finanzen sind nicht erforderlich. Der Schwerpunkt liegt auf dem Verständnis von Konzepten und nicht auf mathematischer Strenge, sodass das Buch einen schnellen Einstieg in die Finanzanalyse für Leser mit quantitativem Hintergrund bietet und dabei jene mathematischen Bereiche hervorhebt, die für die Lösung von Problemen im Finanz- und Vermögensrisikomanagement besonders relevant sind. Ein besonderes Merkmal dieses Buches ist die gleichzeitige Behandlung von zeitkontinuierlicher und zeitdiskreter Finanzmathematik: Quantitative Methods in Finance beschränkt sich damit nicht nur auf die Anwendung der Mathematik in der Finanzwelt, sondern erläutert in didaktisch vorbildlicher Weise, wie diese beiden Disziplinen zusammenwirken – ein umfassender, gut zugänglicher Leitfaden, der Lesern die Werkzeuge an die Hand gibt, ihr Wissen sofort anzuwenden. Der gesamte vierbändige Satz Market Risk Analysis veranschaulicht nahezu jeden Begriff und jede Formel anhand eines praktischen numerischen Beispiels oder einer ausführlicheren empirischen Fallstudie. Über alle vier Bände hinweg finden sich rund 300 numerische und empirische Beispiele, 400 Grafiken und Abbildungen sowie 30 Fallstudien, von denen viele in interaktiven Excel-Tabellen auf der beiliegenden CD-ROM enthalten sind. Empirische Beispiele und Fallstudien speziell für diesen Band umfassen: Hauptkomponentenanalyse europäischer Aktienindizes; Kalibrierung der Student-t-Verteilung mittels Maximum-Likelihood-Methode; Orthogonale Regression und Schätzung von Aktienfaktormodellen; Simulationen der geometrischen Brownschen Bewegung und korrelierter Student-t-Variablen; Bewertung europäischer und amerikanischer Optionen mit Binomialbäumen sowie europäischer Optionen mit der Black-Scholes-Merton-Formel; Kubische Spline-Anpassung von Zinskurven und impliziten Volatilitäten; Lösung des Markowitz-Problems ohne Leerverkäufe und mit weiteren Nebenbedingungen; Berechnung risikoadjustierter Performancekennzahlen, darunter das verallgemeinerte Sharpe-Verhältnis sowie Omega- und Kappa-Indizes.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:37:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('0ILKr91IJxYr', 'Market Risk Analysis, Vol. IV: Value-at-Risk Models', 'Carol Alexander', 2008, 'Finance', 'finance', 'English', '9780470998014', 'Wiley', 432, 4.6, 16, NULL, 'Volume II', 'Market Risk Analysis', 4, '["Business & Economics"]', 'https://www.amazon.com/dp/0470998010', 'https://m.media-amazon.com/images/I/51TDrY9ld+L.jpg', 'Verfasst von der führenden Wissenschaftlerin im Bereich Marktrisiko, Professorin Carol Alexander, ist Practical Financial Econometrics der zweite Band des vierbändigen Werks Market Risk Analysis. Er führt in die ökonometrischen Methoden ein, die in der Finanzwelt gängig sind – mit einer kritischen und gezielten Darstellung, die jene Bereiche der Ökonometrie besonders betont, wie etwa GARCH, Kointegration und Kopulas, die für die Lösung von Problemen in der Marktrisiko-Analyse unerlässlich sind. Das Buch deckt den Stoff eines einsemestrigen Masterkurses in angewandter Finanzökonometrie in didaktisch vorbildlicher Weise ab: Jedes neu eingeführte Konzept wird unmittelbar anhand eines empirischen Beispiels veranschaulicht, das wann immer möglich durch eine Excel-Tabelle illustriert wird. Der gesamte vierbändige Satz Market Risk Analysis veranschaulicht nahezu jeden Begriff und jede Formel anhand eines praktischen numerischen Beispiels oder einer ausführlicheren empirischen Fallstudie. Über alle vier Bände hinweg finden sich rund 300 numerische und empirische Beispiele, 400 Grafiken und Abbildungen sowie 30 Fallstudien, von denen viele in interaktiven Excel-Tabellen auf der beiliegenden CD-ROM enthalten sind. Empirische Beispiele und Fallstudien speziell für diesen Band umfassen: Faktoranalyse mit orthogonalen Regressionen und unter Verwendung von Hauptkomponentenfaktoren; Schätzung symmetrischer und asymmetrischer GARCH- und E-GARCH-Parameter für Normal- und Student-t-Verteilungen; Normal-, Student-t-, Gumbel-, Clayton- und Normalgemisch-Kopuladichten sowie Simulationen aus diesen Kopulas mit Anwendung auf Value-at-Risk und Portfoliooptimierung; Hauptkomponentenanalyse von Zinskurven mit Anwendungen auf Portfolio-Immunisierung und Asset-Liability-Management; Simulation von Normalgemisch- und Markov-Switching-GARCH-Renditen; Kointegrationsbasiertes Index-Tracking und Pairs-Trading mit Fehlerkorrektur- und Impulsantwortmodellierung; Markov-Switching-Regressionsmodelle (EViews-Code); GARCH-Terminstrukturprognosen mit Volatilitäts-Targeting; Nichtlineare Quantilregressionen mit Anwendungen auf das Hedging.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:37:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('LOAvF1yD8ewv', 'Kursbuch Gesundheit', 'Autor unbekannt', 1992, 'Health', 'health', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/3205743-L.jpg', 'Ein umfassender Ratgeber zu Gesundheitsthemen, der Einblicke in die Erhaltung und Förderung des Wohlbefindens bietet und sich an alle richtet, die ihr Wissen rund um Gesundheit und Wohlbefinden erweitern möchten.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:37:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ep9EIV_oOCNU', 'Das Buch vom guten Benehmen', 'Jacob Ernst von Buggenhagen', 1901, 'Manners and Etiquette', 'reference', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Ein umfassender Ratgeber zu Manieren und Etikette. "Das Buch vom guten Benehmen" von Jacob Ernst von Buggenhagen vermittelt Einblicke in die gesellschaftlichen Normen und das angemessene Verhalten des frühen 20. Jahrhunderts und bietet zeitlose Ratschläge, wie man in verschiedenen sozialen Situationen Anstand und Höflichkeit wahrt.', 'claude-translated-de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-14 13:37:07');
