INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('prCM2quNmjbC', 'Eselsbrücken (Duden)', 'Wolfgang Riedel', 2015, 'Reference', 'reference', 'German', '9783411041848', 'Duden', 128, 4.2, 92, NULL, '2.', NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/4110/4184/8/9783411041848xxl.webp', 'Eselsbrücken sind kluge Sätze, die handfeste Informationen unvergesslich machen - und das seit Generationen! Wie erinnern wir uns an das "Gründungsjahr Roms" und an die "Reihenfolge der Planeten" oder dass man "nämlich ohne h schreibt" und dass "afrikanische Elefanten lange Ohren haben"? Diese Sammlung von mehr als 200 altbekannten und weniger bekannten Eselsbrücken samt eingängigen Erläuterungen bietet einen Fundus an Allgemeinbildung aus den Themengebieten Geschichte, Sprache, Geografie, Naturwissenschaften, Mathematik, Kunst und Alltagswissen. Mit ausführlichem Register zum schnellen Nachschlagen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:55:12');
