INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Rj3bmInoyjN2', 'Charttechnik – simplified', 'John J. Murphy', 2005, 'Finance', 'finance', 'German', '9783898791687', 'FinanzBuch Verlag', 83, 3.3, 8, NULL, '1.', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/61KohwefuhL.jpg', 'An der Technischen Analyse kommt heute kein seriöser Trader oder Investor mehr vorbei. Das wichtigste Instrument dabei: die Charttechnik. Ein Chart ist hierbei ein Diagramm, das den Kursverlauf des Wertpapiers über einen bestimmten Zeitraum darstellt. In diesem simplifi ed- Buch erklärt Ihnen John Murphy leicht verständlich und umfassend alle Grundlagen, um an den Finanzmärkten erfolgreich zu traden. Charts sind das Herz der Technischen Analyse. Er führt Sie umfassend in die Welt der Chartdiagramme ein, von Widerstandslinien bis V-Bottom, von Balkencharts bis Candlesticks. Das leicht verständlich und umfassend Einsteiger-Buch für alle, die ihre Anlageerfolge entscheidend verbessern wollen. Mehr lesen', 'amazon_de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-13 22:43:46');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('zTIAqZJoeXyH', 'Technische Analyse – simplified', 'Pierre M. Daeubner', 2005, 'Technical Analysis', 'finance', 'English', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8616662-L.jpg', 'Ein umfassender Leitfaden zum Verständnis und zur Anwendung der technischen Analyse an Finanzmärkten, verfasst von Pierre M. Daeubner, mit dem Ziel, komplexe Konzepte für Leser verständlich zu machen, die praktische Einblicke suchen.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:41:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('g2JBSQMPvRJ6', 'GRASP – The Solution', 'Chris Griffiths; Melina Costi', 2011, 'Business/Personal Development', 'business', 'English', '9781905493951', 'Proactive Pr', 290, 4.4, 31, NULL, NULL, NULL, NULL, '["Business & Economics"]', NULL, 'https://books.google.com/books?vid=ISBN9781905493951&printsec=frontcover&img=1&zoom=3', 'Innovation unterscheidet einen Anführer von einem Nachfolger – wer möchten Sie sein? GRASP The Solution ist ein erfrischend pragmatischer und klar formulierter Leitfaden für kreative Entscheidungsfindung und Problemlösung. Wer schon immer dachte, Kreativität sei nichts als heiße Luft ohne greifbaren Inhalt, wird nach diesem Buch anders denken.
Wie man die besten Antworten auf alltägliche Herausforderungen findet
Fällt es Ihnen schwer, neue und innovative Ideen zu entwickeln? Haben Sie die Idee, können sie aber nicht umsetzen? Suchen Sie verzweifelt nach den richtigen Antworten? Sind Sie frustriert von gescheiterten Gruppen-Brainstorming-Sitzungen?
Chris Griffiths (Leiter von ThinkBuzan, der Organisation hinter dem Mind Mapping – dem Denkinstrument, das weltweit von Millionen genutzt wird) fordert Sie auf, loszulassen, was Ihre Kreativität hemmt. In nur vier klaren Schritten zeigt er Ihnen, wie Sie mutige, frische Ideen und Lösungen auf systematische Weise entfalten können, um jede Herausforderung mit Innovationskraft zu meistern.
Stimmen zum Buch
«Chris zeigt mit Klarheit und Überzeugungskraft, dass kreatives Denken kein Zaubertrick ist, sondern ein Prozess, der erlernt, entwickelt und – was am wichtigsten ist – auf die Herausforderungen angewendet werden kann, denen wir alle begegnen, ob beruflich oder persönlich. Eine ausgezeichnete Ressource. Greifen Sie zu.» Tim Hurson, Autor von ''Think Better: An Innovator''s Guide to Productive Thinking''
«Chris und seine Arbeit haben mein Leben verändert und weltweit bereits das Leben von Millionen Menschen zum Besseren gewandelt. Seine Arbeit ist dabei, dasselbe für SIE zu tun!» Tony Buzan, Bestsellerautor mit millionenfacher Auflage und Erfinder des Mind Mappings
«Ein Muss mit präzisen Techniken, um Ihren Denkprozess und Ihre Produktivität zu steigern. Ich würde dieses Buch jedem empfehlen, der bereit ist, voranzukommen und Herausforderungen anders zu betrachten. Wenn Sie Ihre Probleme in praktische Lösungen verwandeln möchten, wird dieses Buch Ihnen definitiv helfen.» Philippe Packu, Business-Analyst, Sony
«Unternehmen proklamieren die Notwendigkeit, ''intelligenter zu arbeiten'' – Chris Griffiths liefert einen Fahrplan, wie das gelingt.» Bob Urichuck, Autor von ''Disciplined For Life'' und ''You Are the Author of Your Future''
«Dieses Buch bietet neue Werkzeuge und Techniken rund um Kreativität und Innovation für Ihren persönlichen, beruflichen und gesellschaftlichen Erfolg. Es hilft Ihnen, anders zu denken. Lesen Sie es und werden Sie ein Wegbereiter!» Professor M.S. Rao, internationaler Führungsexperte und Autor von ''Success Sutras Lead Your Life Successfully''
«Wenn alle Chris'' Buch lesen und seine Vorschläge täglich umsetzen würden, kämen wir alle schneller auf den Punkt und gewännen den kostbarsten Schatz: Zeit!» Oriol Marimon-Clos, Geschäftsführer, Ideas Angels
«Chris hat meine Art zu denken und Lösungen zu entwickeln grundlegend verändert und eine kreative Stimme in mir geweckt, von der ich nicht wusste, dass sie existiert.» Ed Allen, Konteradmiral der US Navy (a.D.), Executive Business Coach, Executive Success Group
«Ich habe viele Ideen gewonnen und einen echten Wandel in meinem Denken erlebt.» John Brooker, Yes! And...
«Ich halte Chris Griffiths für eines der großen Talente, die in den kommenden Jahren aufblühen werden.» Ron Kaufman, Bestsellerautor von ''UP Your Service!''
«Chris fordert Menschen heraus, mit ''alten Gewohnheiten'' zu brechen und kreative Ideen für neue Wege zu embracen.» Brenton Nicholls, Direktor, Impact Unlimited
«Chris ist eine seltene Kombination aus Unternehmer und Wirtschaftsexperte: Er beherrscht die gesamte Theorie vollständig, ohne sich in ihr zu verlieren. Stattdessen macht er sie für die reale Welt nutzbar. Dieses Buch ist vielleicht der beste Beweis dafür – es hilft Ihnen nicht nur, bessere Ideen zu entwickeln, sondern sie (und das ist das Entscheidende) auch zum Leben zu erwecken und Wirklichkeit werden zu lassen!» Liam Hu', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:47:37');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('xuUANABLfNWU', 'Mind Maps for Business', 'Tony Buzan; Chris Griffiths', 2008, 'Business', 'business', 'English', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, '["Electronic books"]', NULL, 'https://covers.openlibrary.org/b/id/10558353-L.jpg', 'Das heutige Informationsumfeld erfordert von uns allen, Zeit zu sparen, die Effizienz zu steigern und kreativer zu denken. Mind Mapping ist ein unverzichtbares Geschäftswerkzeug, das Sie Ihrem geistigen Rüstzeug hinzufügen können. Dieser Infoline-Band führt Sie in das Konzept des Mind Mappings ein. Sie lernen, wie man Mind Maps liest und erstellt, Mind Maps für gängige Geschäfts- und Trainingsprozesse einsetzt sowie Kreativität und Leistungsfähigkeit durch den Einsatz von Mind Maps steigert. Trainer können Mind Maps im Besonderen nutzen, um geplante Kurse oder Programme zu skizzieren, einen Geschäftsfall für neue Projekte oder Finanzierungen darzustellen, Inhalte von Trainingsprogrammen zu strukturieren, Ideen während Besprechungen und Trainingseinheiten zu entwickeln sowie Verbindungen zwischen Geschäftsanforderungen und Entwicklungsmaßnahmen herzustellen.', 'claude-translated-de', '2026-05-14 10:08:08', '2026-05-11 23:09:48', '2026-05-14 13:41:27');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('1LWkubeJ76H8', 'Raumfahrt Lexikon', 'Stanislav Stanek', 1983, 'Reference', 'reference', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8157882-L.jpg', 'Ein umfassendes Nachschlagewerk von Stanislav Stanek, das verschiedene Aspekte der Raumfahrt, Technologie und Geschichte ausführlich behandelt. ...', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:41:30');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('MdWx9_cQh8Qx', 'Planeten Lexikon', 'Bruno Stanek', 1979, 'Non-fiction', 'non-fiction', NULL, '9783444102394', 'Hallwag-Verlag', 320, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783444102394&printsec=frontcover&img=1&zoom=3', 'Ein informativer Leitfaden zu den Planeten, der ausführliche Beschreibungen, historischen Kontext und wissenschaftliche Erkenntnisse bietet, verfasst von Richard Stanek.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:41:31');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('tUzebbCnrDES', 'Astronomie', 'Karttunen, Kröger, Oja, Donner, Poutanen', 2018, 'Non-fiction', 'non-fiction', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/9175542-L.jpg', 'Eine Erkundung astronomischer Konzepte und Phänomene, verfasst von Fachleuten auf diesem Gebiet, die Einblicke in die Geheimnisse des Universums und die wissenschaftlichen Grundprinzipien bietet, die es beherrschen.', 'claude-translated-de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 13:41:34');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('JBDr_OCxNTZk', 'Die Kunst der Überlegenheit', 'Donald G. Krause', 1997, 'Business Strategy', 'business', 'Unbekannt', '9783832303440', 'Campus', 144, 4.0, NULL, NULL, '3.', NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783832303440&printsec=frontcover&img=1&zoom=3', 'Das Wesen des Führens zu verstehen und starke Führungsqualitäten herauszubilden, ist eine der wichtigsten Aufgabe heutiger Gesellschaften. Aber bereits in frühen Zeiten galt es als größte Herausforderung, Führungsqualitäten zu beweisen, vor allem dann, wenn die Bedingungen extrem schwierig waren. In diesem Zusammenhang kommt zwei Männern aus dem alten China ganz besondere Bedeutung zu: dem berühmten Feldherrn Sun Tzu und dem großen Philosophen Konfuzius. Kombiniert man ihre beiden Konzepte des Führens, so ergibt das ein System, das auch unter den schwierigsten Bedingungen funktioniert. Diesen Ansatz greift der Autor auf und überträgt die herausragenden militärischen und politischen Ideen direkt auf moderne Wirtschaftssituationen. Er bringt die philosophischen Visionen Sun Tzus und Konfuzius'' auf den Punkt und schafft so eine "Straßenkarte zum Erfolg". Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:52:19');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('N7WHvMmE5nwN', 'Spieltheorie für Führungskräfte', 'Volker Bieta; Wilfried Siebe', 1998, 'Business/Economics', 'finance', 'German', '9783832304096', 'Redline Wirtschaftsverlag', NULL, 5.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/8323/0409/6/9783832304096xxl.webp', 'Die Spieltheorie ist spätestens seit der Verleihung des Nobelpreises für Wirtschaftswissenschaften an den Deutschen Reinhard Selten auch hierzulande ein Begriff. Ohne mathematische Formeln und wissenschaftlichen Fachjargon erklärt dieses erste originär deutschsprachige Buch zur hochaktuellen Thematik anhand von vielen realen Beispielen, wie die Spieltheorie funktioniert, was sie leisten und was sie nicht leisten kann. Die Faktoren -Spieler-, -Strategie-, -Information-, -Wertschöpfung- und -Spielregeln- bestimmen das Spiel. Sie sind die Hebel, an denen angesetzt werden muss, um Spiele nach eigenen Zielen zu gestalten und zu verändern. Die Spiele sind Szenarien. Erst die gedankliche Disziplin, in der Spieltheorie gibt dann den (Management-)Szenarien die notwendige klare, auf wenige strategisch relevante Kernpunkte reduzierte Struktur. Durch den (Gedanken-)Rahmen der Spiele wissen die Spieler, was sie tun soll(t)en - und vor allem, wie sie es tun müssen, um ihre Ziele zu realisieren . Die Spieltheorie zeigt, wie man in konkreten Entscheidungssituationen die richtigen Entscheidungen finden kann, neue Sichtweisen von Situationen gewinnt und -Lösungen- in die Praxis umsetzt. Die anschaulichen Beispiele stammen zum großen Teil aus dem militärischen Bereich (Hannibal, Napoleon, Erster und Zweiter Weltkrieg, Golfkrieg), aber auch aus dem zivilen Leben (Krankenhaus-Management, Bank- und Börsengeschehen). Inzwischen haben auch amerikanische Business Consultants den Wert der Spieltheorie als Strategiepraktik für nichtmilitärische Zwecke erkannt. Für die erfolgreiche Umsetzung spieltheoretischer (Denk-)Logik in die Management-Praxis ist der Harvard-Management-Professor Michael Porter ein weltberühmter Zeitzeuge. Viele Regierungen und verschiedenste Organisationen in der ganzen Welt ziehen Spieltheoretiker als Berater heran. Noch dazu ist dieses bahnbrechende Buch auch eine Tour d-horizon durch die Geschichte des strategischen Denkens. Mehr lesen', 'amazon_de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-13 23:07:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Pjsb7xybsDTu', 'Elon Musk: Tesla, SpaceX, and the Quest for a Fantastic Future', 'Ashlee Vance', 2023, 'Biography', 'biography', 'Spanish', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8463846-L.jpg', 'Eine Biografie, die das Leben und die Leistungen von Elon Musk beleuchtet, mit einem Schwerpunkt auf seinen Unternehmungen bei Tesla, SpaceX und anderen bahnbrechenden Projekten. Sie gewährt Einblicke in seinen Antrieb, seinen Erfindergeist und seinen Einfluss auf die Zukunft der Technologie.', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:41:36');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('nmKezVUlnOi_', 'Gewinnen mit Börsenzyklen', 'Thomas Müller', 2007, 'Finance', 'finance', 'German', '9783930851652', 'TM Börsenverlag', 258, 3.3, 8, NULL, '4., Aufl.', NULL, NULL, '["Börsenkurs - Zyklus - Prognose 2005-2010"]', NULL, 'https://m.media-amazon.com/images/I/A1bh7Nm-wcL.jpg', 'Gewinnen mit Börsenzyklen Jeder Anleger kennt Jahresanfangs-Rallyes, Jahresend-Rallyes und die Sommerkorrekturen der Börsen. Diese Börsenphasen entstehen aber nicht zufällig, sondern wiederholen sich permanent, folgen also einem zyklischen Muster. Gewinnen mit Börsenzyklen zeigt anhand der kompletten Kurshistorie von Dax (seit 1959) und Dow Jones (seit 1896) den typischen zyklischen Kursverlauf der Börsen. Dabei wird eine detaillierte Untersuchung aller Jahres-Zyklen, Wahl-Zyklen, Zyklen der 4-Jahres-Tiefs, unterjährigen Zyklen und Jahrzehnt-Zyklen vorgenommen, so dass Gesamtverlauf und damit Start und Ende der entsprechenden Zyklen klar und nachvollziehbar werden. In insgesamt 31 Zyklen-Portfolios werden darauf basierende Anlagemodelle vorgestellt, die fast ohne Aufwand und mit einem deutlich reduzierten Risiko eine massive Outperformance von Dax und Dow Jones ermöglichen. Gegenüber einer Buy-and-Hold-Strategie lassen die Gewinne unter zu Hilfenahme von Zyklen sogar um das bis zu 33-fache steigern! Daneben zeigt eine ausführliche Besprechung der Demographie-Zyklen und der Technologie-Zyklen, warum die nächsten Jahre außergewöhnliche Börsenperspektiven eröffnen. Als Zusammenfassung aller behandelten Zyklen ergeben sich folgende Prognosen: - Dax und Dow Jones haben die Tiefs des Jahrzehnts schon hinter sich! - Die laufende Hausse wird sich bis 2009/2010 fortsetzen! - Das Mindestkursziel sind 10.000 für den Dax und 26.000/29.000 für den Dow Jones! - Vielleicht entsteht aber sogar eine noch viel größere Börsenblase als 1999/2000. Das würde bis Ende des Jahrzehnts zu noch deutlich höheren Notierungen führen, worauf ab 2010 aber eine Extrem-Baisse folgen sollte! Das Buch erklärt alle dominierenden Zyklen und skizziert daraus das wahrscheinlichste Bild für den Börsenverlauf der nächsten Jahre. Gewinnen mit Börsenzyklen ist das ultimative Basiswerk zu einem bisher fast unbekannten Analyseansatz, der in den nächsten Jahren noch erheblich an Popularität gewinnen wird. Mehr lesen', 'amazon_de', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:59:28');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Hb5oLXeEdba-', 'Die 24 Geheimnisse des George Soros', 'Robert Slater', 1998, 'Biography', 'biography', 'German', '9783832304126', 'Ueberreuter', 166, 5.0, NULL, NULL, '3.', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/71m9Vg9mERL.jpg', 'George Soros war bis zum Herbst 1992 nur wenigen außerhalb des Exklusivkreises der Hochfinanz ein Begriff. Das änderte sich schlagartig im September 1992: Er setzte darauf, daß Großbritannien aufgrund der immer flauer werdenden Wirtschaftslage zu einer Abwertung des britischen Pfundes gezwungen sein würde - und seine Spekulation ging auf. Als das Pfund am 15. September 1992 tatsächlich abgewertet wurde, verdiente Soros buchstäblich über Nacht eine Milliarde Dollar. - Ein Star war geboren. George Soros nimmt unbestritten den Rang des weltweit berühmtesten Investors ein. Kein anderer hat über einen so langen Zeitraum hinweg derart hervorragende Ergebnisse erzielt wie Soros. Einen besseren Lehrer als George Soros gibt es nicht. Seit 1969, dem Gründungsjahr seines Quantum-Fonds, hat Soros mit seinen Investitionen einen unglaublichen Rekord aufgestellt. Ein im Jahr 1969 in den Quantum-Fonds investierter Betrag von 1.000 Dollar wäre bei Wiederveranlagung der Dividenden bis zum Jah r 1995 auf 2,150.000 Dollar angewachsen. Dieses Buch gewährt einen Einblick in Soros'' Anlagestrategien. Viele dieser Denkansätze sind für den Kleinanleger ebenso anwendbar wie für den professionellen Investor. Zwar ist die Kenntnis der Geheimnisse hinter Soros'' Investitionserfolgen sicherlich keine Garantie dafür, daß der Leser über Nacht eine Milliarde Dollar verdienen wird. Doch kann er, indem er sich ein Bild von der Denk- und Arbeitsweise George Soros'' verschafft und seine Schlüsselstrategien gedanklich nachvollzieht, zu einem besseren Verständnis der komplexen Welt der Hochfinanz gelangen; er kann selbst ein gewisses Gespür dafür entwickeln, das Geschehen in den Finanzmärkten richtig zu interpretieren und daraus Gewinne zu erzielen. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:51:51');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('AKs8bwhz5wpq', 'Sovereign Risk Analysis: A New Qualitative Hybrid Approach for Early Warning', 'Autor nicht eindeutig', NULL, 'Finance/Economics', 'finance', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Eine umfassende Untersuchung der Staatsrisikobewertung, die einen neuartigen qualitativen Hybridansatz zur Früherkennung vorstellt und darauf abzielt, Vorhersage und Steuerung in Finanz- und Wirtschaftsbereichen zu verbessern.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:41:39');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('nDA6FRrvO91s', 'Charisma', 'Nikolaus B. Enkelmann', 2000, 'Self-help', 'self-help', 'German', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/3212205-L.jpg', 'Ein Ratgeber von Nikolaus B. Enkelmann, erschienen im Jahr 2012, der das Konzept des Charismas beleuchtet und praktische Hinweise gibt, wie man persönliche Ausstrahlung und Überzeugungskraft entwickeln und stärken kann.', 'claude-translated-de', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-14 13:41:42');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('TyfsRx6-bL_9', 'Die Kunst des Krieges für Führungskräfte', 'Donald G. Krause', 1996, 'Business Strategy', 'business', 'German', '9783832301866', NULL, 150, 3.5, 11, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783832301866&printsec=frontcover&img=1&zoom=3', 'Ein strategisches Wirtschaftsbuch, das die alte Weisheit aus Sun Tzus «Die Kunst des Krieges» in praktische Ratschläge für Führungskräfte und Manager überträgt und Einblicke in wirksame Entscheidungsfindung, Unternehmensführung und Wettbewerbsstrategien in der Geschäftswelt bietet.', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:47:40');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('HQqA2_9lzZih', 'Es war einmal ein Zebra, das liebte die Algebra', 'Markus Marty', 2019, 'Children''s Literature', 'children''s-literature', 'German', '9783990184806', 'Bucher Verlag GmbH', 56, 5.0, NULL, NULL, '1.', NULL, NULL, NULL, NULL, 'https://exlibris.azureedge.net/covers/9783/9901/8480/6/9783990184806xxl.webp', 'Die köstlichen, spannenden Ministorys, zu heiter berührenden Versen verdichtet, sprühen vor Lebensfreude. Marty nutzt dabei die Tiefe und Bedeutungsvariationen der Worte und bietet dem Leser so die Möglichkeit, in eine weitere Ebene einzutauchen. Wie ansonsten bei seiner Arbeit mit Düften, geht der Parfumeur hier auf die »Seele« der Worte ein. Ein Geschenk im besten Sinne des Wortes. Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:54:24');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('ZSU3ip4wncWj', 'Rhetorik – Handbuch der Redekunst (Band 2)', 'Roman Hofmeister', 1993, 'Non-Fiction', 'non-fiction', 'German', '9783850122641', 'Weltbild, Augsburg,', 600, 5.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://pictures.abebooks.com/isbn/9783850122641-de-300.jpg', 'Ein umfassendes Werk zur Kunst der Rhetorik: Dieser Band von Roman Hofmeister widmet sich fortgeschrittenen Techniken und Strategien für wirkungsvolles öffentliches Sprechen und bietet Einblicke in Überzeugungskunst, Publikumsansprache und die Gestaltung von Reden. Das 2020 erschienene Buch ist ein unverzichtbares Nachschlagewerk für alle, die ihre Ausdrucksfähigkeit in verschiedenen Bereichen verfeinern möchten.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:41:48');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('1B-T-NtWTJbF', 'Rhetorik – Handbuch der Redekunst (Band 1)', 'Roman Hofmeister', 1993, 'Non-fiction', 'non-fiction', 'German', '9783850122641', 'Weltbild, Augsburg,', 600, 5.0, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/61ft-dIgvXL.jpg', 'Umfassender Leitfaden zur Kunst der Rhetorik, der Einblicke in wirkungsvolles öffentliches Sprechen und überzeugende Kommunikationstechniken bietet.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:41:50');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('rk9xerhM7ofC', 'Die 222 wichtigsten Fragen zu Derivaten', 'Volker Meinel', 2007, 'Finance', 'finance', 'German', '9783898792110', 'FinanzBuch Verlag', 256, 3.0, NULL, NULL, '1.', NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783898792110&printsec=frontcover&img=1&zoom=3', 'Ob Optionen, Futures oder Swaps – die Welt der Derivate ist vielfältig und für Privatanleger nicht immer leicht zu durchschauen. Oft können einem auch Banken und Anlageberater nicht weiterhelfen. Volker Meinel, selbst Banker mit einem offenen Ohr für seine Kunden, kämpft gegen diesen Missstand an. Nun hat Meinel seine jahrelangen Erfahrungen in 222 Fragen und Antworten zusammengefasst. Der Leser erhält einen optimalen Überblick über die Märkte und ist in der Lage, selbst erfolgreich an den weltweiten Finanzmärkten zu bestehen. - Der Autor bringt seine Erfahrung aus unzähligen Leserbriefen, Telefonaten und Messegesprächen ein - Ein weiteres Highlight aus der Reihe »Die 222 wichtigsten Fragen zu …« - Umfassende Einblicke in die Welt der Derivate - Durch das Frage-Antwort-Schema übersichtlich gegliedert Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:51:24');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6r6T20vq5oOS', 'Forex Conquered', 'John L. Person', 2007, 'Finance', 'finance', 'English', '9780470127049', 'John Wiley & Sons', 306, NULL, NULL, NULL, NULL, NULL, NULL, '["Business & Economics"]', NULL, 'https://exlibris.azureedge.net/covers/9780/4701/2704/9/9780470127049xxl.webp', 'Lobeshymnen auf FOREX CONQUERED
«In diesem erstaunlichen Buch deckt John alles ab. Von Handelssystemen über Geldmanagement bis hin zu Emotionen erklärt er verständlich, wie man dem kompliziertesten Finanzmarkt der Welt beständig Gewinne entlockt. John packt mehr neue, innovative Informationen in dieses Buch, als ich je zuvor in einem Handelsbuch gesehen habe.»
— Rob Booker, unabhängiger Devisenhändler
«John Person gehört zu den wenigen seltenen Talenten, die auf einzigartige Weise dazu befähigt sind, Händlern den Prozess des erfolgreichen Handels näherzubringen. Angesichts der zunehmenden Herausforderungen der heutigen Märkte hat John das Wesentliche herausgearbeitet und die dringend benötigten Werkzeuge des Devisenhandels in den Vordergrund gestellt. Diese klar strukturierte und gut organisierte Publikation ist ein bedeutender Schritt nach vorn, um Händlern einen Vorsprung zu verschaffen. Ich empfehle Forex Conquered wärmstens als wertvolles Handbuch für aufstrebende wie erfahrene Händler gleichermaßen.»
— Sandy Jadeja, Chefmarktanalyst und Redakteur, London Stock Exchange, London, England
«Forex Conquered ist ein gewagter Titel, doch dieses Buch liefert tatsächlich die Werkzeuge, die für einen erfolgreichen Devisenhandel benötigt werden. Kein Füllmaterial, nur die Weisheit eines Handelsveteranen, dem ich stets Respekt entgegengebracht und den ich stets verfolgt habe.»
— Michael Kahn, Redakteur, Quick Takes Pro market letter und Kolumnist, Barron''s Online
«Dies ist eine wunderbare, tiefgehende Einführung in die technische Analyse und umsichtige Geldmanagement-Richtlinien im Devisenmarkt.»
— Blake Morrow, Präsident, 4XMadeEasy
«Forex Conquered ist ein bedeutender Beitrag zur wachsenden Zahl von Büchern über den Devisenhandel. John Person bietet einen professionellen Blick auf den Devisenhandel, den Leser als Leitfaden für funktionierende Strategien und Taktiken nutzen können. Der Umfang des Buches geht über den Devisenhandel hinaus und umfasst wesentliche Aspekte des Termin- und Optionshandels. Es sollte gelesen – und dann erneut gelesen werden!»
— Abe Cofnas, Präsident, Learn4x.com
Hinweis: CD-ROM/DVD und anderes ergänzendes Material sind nicht Bestandteil der E-Book-Datei.', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:47:52');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('8uo8rUuYgdhc', 'Der Schwarze Schwan', 'Nassim Nicholas Taleb', 2021, 'Non-fiction', 'non-fiction', 'German', '9783641281779', 'Penguin Verlag', 810, NULL, NULL, NULL, NULL, NULL, NULL, '["Social Science"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6412/8177/9/9783641281779xxl.webp', 'Die Weltbestseller des großen Zufallsforschers Ein “Schwarzer Schwan” ist ein Ereignis, auf das drei Dinge zutreffen: Es ist erstens ein Ausreißer – es liegt außerhalb der regulären Erwartungen, nichts in der Vergangenheit weist darauf hin. Es hat zweitens enorme Auswirkungen. Drittens bringt uns die menschliche Natur dazu, im Nachhinein Erklärungen für sein Eintreten zu konstruieren, um es erklärbar und vorhersagbar zu machen. In diesem bahnbrechenden Buch, das mittlerweile weltweit zum Klassiker geworden ist, entwickelt Taleb seine einflussreiche Denkfigur und Maxime für die ungewisse Realität, in der wir leben und handeln. Talebs Weltbestseller – „Der Schwarze Schwan: Die Macht höchst unwahrscheinlicher Ereignisse“ und „Der Schwarze Schwan: Konsequenzen aus der Krise“ – in einem Band und eingeleitet mit einem neuen Essay des Autors »Eines der zwölf einflussreichsten Bücher seit dem Zweiten Weltkrieg.« (Sunday Times) »›Der Schwarze Schwan‹ hat meine Sicht auf die Welt verändert.« (Daniel Kahneman, Nobelpreisträger) Der Weltbestseller: übersetzt in 33 Sprachen mit über 3 Millionen verkauften Exemplaren »Taleb zerpflückt mit großer Lust und einem guten Schuss Polemik unseren offenbar unerschütterlichen Glauben an die Vorhersehbarkeit von Ereignissen.« (SWR)', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:48:41');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('0XjBem6mtHxK', 'Zeitmanagement mit Outlook', 'Schwert; Wagner; Obermayr', 2010, 'Non-fiction', 'non-fiction', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/9531099-L.jpg', 'Ein umfassender Leitfaden zur Nutzung von Microsoft Outlook für effektives Zeitmanagement, verfasst von Schwert, Wagner und Obermayr. Dieses Sachbuch bietet Strategien und Tipps zur Steigerung der Produktivität und zur Organisation von Aufgaben mithilfe der Funktionen von Outlook.', 'claude-translated-de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 13:42:04');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('MfS9FyVvUd9f', 'Fighter Wing', 'Tom Clancy', 2007, 'Military Fiction', 'thriller', 'English', '9781101002575', 'Penguin', 386, NULL, NULL, NULL, NULL, NULL, NULL, '["History"]', NULL, 'https://exlibris.azureedge.net/covers/9781/1010/0257/5/9781101002575xxl.webp', 'Zum ersten Mal ein Einblick von innen in einen Kampfverband der Air Force – die Flugzeuge, die Technologie und die Menschen … mit Tom Clancy als Ihrem Führer. Tom Clancys frühere Erkundungen der amerikanischen Streitkräfte, Submarine und Armored Cav, enthüllten exklusive, nie zuvor veröffentlichte Informationen über die Menschen und die Technologie, die unsere Nation schützen. Nun begibt sich der gefeierte Autor von Clear and Present Danger und Debt of Honor mit der Elite der U.S. Air Force auf Höhenflug: dem Fighter Wing. Mit seinem mitreißenden Stil und seinem untrüglichen Blick fürs Detail fängt Clancy den Rausch des Starts, die Dramatik des Luftkampfes und die unablässigen Gefahren ein, denen unsere Kampfpiloten jeden Tag ihres Lebens ausgesetzt sind … und zeigt den Lesern, was es wirklich bedeutet, zur absoluten Elite zu gehören. Fighter Wing enthält: Detaillierte Analysen der führenden Kampfflugzeuge der Air Force, darunter den F-15 Eagle – Exklusive Fotografien, Illustrationen und Diagramme – Einen Einblick von innen in die Menschen hinter den Flugzeugen und Waffen – Kampfstrategien und Ausbildungsmethoden der U.S. Air Force', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:42:11');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('auoumYaNtDDw', 'Das Echo aller Furcht', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641089924', 'Heyne Verlag', 951, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8992/4/9783641089924xxl.webp', 'Der Kalte Krieg scheint Vergangenheit, die Weltmächte verhandeln im Zeichen der Kooperation und setzen auf eine friedliche Zukunft. Doch hinter den Kulissen tickt eine gefährliche Zeitbombe, und ein seltsamer Bombenfund genügt, um einen weltumspannenden tödlichen Konflikt zu entfachen. Jack Ryan, Amerikas Geheimdienstmann für Top-Secret-Fälle, muss einen nahezu aussichtslosen Kampf gegen die Zeit gewinnen ...', 'google_books', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-13 22:44:33');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('fujtRVEV0NDu', 'Rainbow Six', 'Tom Clancy', 1998, 'Techno-thriller', 'thriller', 'Chinese', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/3100545-L.jpg', 'Ein actionreicher Techno-Thriller über eine multinationale Eliteeinheit zur Terrorismusbekämpfung namens Rainbow, die unter der Führung von John Clark mit modernster Technologie und packenden Taktikoperationen verschiedene globale Bedrohungen bekämpft.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:42:13');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('v22xVeqgfmdQ', 'Im Auge des Tigers', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641085803', 'Heyne Verlag', 398, 4.5, 2, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8580/3/9783641085803xxl.webp', 'Die neue Form des internationalen Terrorismus fordert eine neue Generation von Jägern heraus: Es kommt die Zeit für Jack Ryan, Jr. und seinesgleichen. Ein Mann namens Mohammed sitzt in einem Wiener Kaffeehaus und schlägt einem Kolumbianer ein Geschäft vor: Mohammed hat ein starkes Netzwerk aus Agenten und Sympathisanten in ganz Europa und im Mittleren Osten, und der Kolumbianer ein ähnlich starkes Netzwerk im Drogenhandel Amerikas. Warum sollten sie nicht eine Allianz bilden? Das Potential für Profit wäre riesengroß – und das Potential für Zerstörung unvorstellbar.', 'google_books', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:00:30');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('LpzIOoT90DCE', 'Der Kardinal im Kreml', 'Tom Clancy', 2012, 'Techno-thriller', 'thriller', 'German', '9783641088576', 'Heyne Verlag', 422, 5.0, 1, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8857/6/9783641088576xxl.webp', 'Von einem geheimen Ort in der Nähe der afghanischen Grenze aus haben Russen erstmals mit einem Laserstrahl einen US-Spionagesatelliten "geblendet". Ein Fall für Jack Ryan. «Ein Autor, der nicht in Science-fiction abdriftet, sondern realistische Ausgangssituationen spannend zum Roman verdichtet.» DER SPIEGEL', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:47:42');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('T9Z8XM8Gd0qC', 'Im Sturm', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641089917', 'Heyne Verlag', 768, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8991/7/9783641089917xxl.webp', 'Das Attentat arabischer Fundamentalisten auf eines der wichtigsten Ölfelder Sibiriens bringt die GUS in einen fatalen Zugzwang. Um den Zusammenbruch ihrer maroden Wirtschaft zu verhindern, erzwingt Moskau sich Zugang zum Persischen Golf und schreckt auch vor einem Schlag gegen die NATO nicht zurück ...', 'google_books', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-13 23:01:02');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('5MjlkjYcDpo6', 'Der Schattenkrieg', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641089900', 'Heyne Verlag', 615, 5.0, 2, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8990/0/9783641089900xxl.webp', 'Als kolumbianische Drogenbosse drei hochrangige US-Amerikaner töten, ist für den Geheimdienstmann Jack Ryan der Punkt erreicht, an dem er zurückschlagen muss. Er stellt eine Truppe kampferprobter Männer zusammen und führt sie in einen Schattenkrieg, in dem die üblichen Regeln nicht gelten.', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:48:13');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Vgbq-K_Y1G-N', 'Gnadenlos', 'Tom Clancy', 2017, 'Thriller', 'thriller', 'German', '9783641226640', 'Heyne Verlag', 699, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6412/2664/0/9783641226640xxl.webp', 'John Kelly, ehemaliger US-Marine und Spezialist für riskante Missionen, erhält den Auftrag, amerikanische Geiseln aus Nordvietnam herauszuholen - eine beinahe aussichtslose Mission, zumal Kelly sich gerade durch einen privaten Rachefeldzug in Lebensgefahr gebracht hat. Ein Wettlauf gegen die Zeit beginnt, und der geringste Fehler könnte sein letzter sein ...', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 23:00:00');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('Wst-0OfzmhAb', 'Befehl von oben', 'Tom Clancy', 2013, 'Thriller', 'thriller', 'German', '9783641089061', 'Heyne Verlag', 1098, NULL, NULL, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8906/1/9783641089061xxl.webp', 'Jack Ryans schwerste Stunde Bei einem Flugzeugangriff auf das Kapitol kommt der amerikanische Präsident ums Leben. Spezialagent Jack Ryan, vor Kurzem zum Vizepräsidenten ernannt, muss von einem Tag auf den anderen die Amtsgeschäfte übernehmen. Derweil nutzen Amerikas Feinde ihre Chance: China und Taiwan stehen kurz vor einem Krieg, und der Iran plant, amerikanische Großstädte mit einem tödlichen Virus zu verseuchen ...', 'google_books', '2026-05-14 10:07:54', '2026-05-11 23:09:48', '2026-05-13 22:42:07');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('2__5JtUXjJ_D', 'Ehrenschuld', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783453436787', 'Heyne Verlag', 1040, 4.4, 941, NULL, NULL, 'Jack Ryan', 8, NULL, NULL, 'https://m.media-amazon.com/images/I/91DSsW0hdEL.jpg', 'Jack Ryans härtester Einsatz Außenpolitisch stehen die USA kurz vor der Alarmstufe Rot. Man holt Jack Ryan als neuen Sicherheitsberater des Präsidenten an die vorderste Front. Doch bevor er loslegt, muss Ryan zuerst noch eine Ehrenschuld begleichen. Ein Politthriller der Sonderklasse! Mehr lesen', 'amazon_de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:53:20');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('EbX3iNmGXb2U', 'Im Zeichen des Drachen', 'Marc Olden', 2001, 'Thriller', 'thriller', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/2206056-L.jpg', 'Ein packender Thriller vor dem Hintergrund internationaler Spionage und Intrigen. »Im Zeichen des Drachen« erzählt eine vielschichtige Geschichte über Machtkämpfe und geheime Operationen. Als die Spannungen zunehmen, müssen sich die Protagonisten in einer Welt voller Gefahr und Täuschung behaupten, in der Loyalitäten auf die Probe gestellt werden und nichts so ist, wie es scheint.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:42:16');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('-X1sZeJKiOPm', 'Gegen alle Feinde', 'Tom Clancy', 2012, 'Thriller', 'thriller', 'German', '9783641085827', 'Heyne Verlag', 741, 4.0, 13, NULL, NULL, NULL, NULL, '["Fiction"]', NULL, 'https://exlibris.azureedge.net/covers/9783/6410/8582/7/9783641085827xxl.webp', 'Internationale Intrigen, explosive Action – der neue große Tom Clancy Seit Jahren tobt der Konflikt im Mittleren Osten. Nun sieht es so aus, dass sich der Kriegsschauplatz verlagert hat. Die Taliban bedienen sich für ihre Machenschaften eines mexikanischen Drogenkartells und tragen den Kampf ins Heimatland des Erzfeindes – in die Vereinigten Staaten von Amerika. Tom Clancy, der Meister des internationalen Politthrillers, stellt uns seinen neuen Helden vor: Ex-Navy-SEAL Max Moore. Und der steht allein – gegen alle Feinde.', 'google_books', '2026-05-14 10:08:02', '2026-05-11 23:09:48', '2026-05-13 22:58:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6nC6RXBto_LU', 'Ziel erfasst', 'Tom Clancy', 2014, 'Thriller', 'thriller', NULL, '9783453267398', 'Heyne', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://books.google.com/books?vid=ISBN9783453267398&printsec=frontcover&img=1&zoom=3', 'Ein hochspannender Thriller aus der Welt der Spionage und militärischen Taktik, in dem ausgeklügelte Verschwörungen und internationale Intrigen die Figuren zwingen, ein gefährliches Katz-und-Maus-Spiel zu bestehen.', 'claude-translated-de', '2026-05-14 10:08:12', '2026-05-11 23:09:48', '2026-05-14 13:42:18');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('M366WVN8yNge', 'The European Dream', 'Jeremy Rifkin', 2004, 'Non-fiction', 'non-fiction', 'Spanish', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/483335-L.jpg', 'The European Dream von Jeremy Rifkin untersucht die sich wandelnde europäische Identität und stellt sie dem amerikanischen Traum gegenüber. Das Buch beleuchtet, wie Europas Vision Gemeinschaft, Nachhaltigkeit und Lebensqualität über individuellen Erfolg und materiellen Wohlstand stellt. Rifkin argumentiert, dass das europäische Modell einer globalisierten Welt eine zukunftsfähigere und gerechtere Perspektive bietet.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:42:22');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('R4trCgIlkTfv', 'The Age of Access', 'Jeremy Rifkin', 2000, 'Non-fiction', 'non-fiction', 'English', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/6798299-L.jpg', 'Eine fesselnde Untersuchung darüber, wie der Wandel vom Eigentum zum Zugang Wirtschaft, Kultur und Alltag verändert – einer Welt, in der traditionelle Märkte zunehmend durch Netzwerke und Dienstleistungen ersetzt werden.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:42:24');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('9KZtm5uDMO4Q', 'The Hydrogen Economy', 'Jeremy Rifkin', 2002, 'Non-fiction', 'non-fiction', 'Russian', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/850150-L.jpg', 'Erkundet das Potenzial von Wasserstoff als nachhaltige Energiequelle und seine Rolle bei der Bewältigung globaler Energie- und Umweltherausforderungen.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:38:12');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('KSL8EN6lEW-Q', 'The Biotech Century', 'Jeremy Rifkin', 1998, 'Non-fiction', 'non-fiction', 'German', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/666192-L.jpg', 'Untersucht die tiefgreifenden Auswirkungen der Biotechnologie auf Gesellschaft, Wirtschaft und das menschliche Erleben, und analysiert sowohl die möglichen Vorteile als auch die ethischen Bedenken im Zusammenhang mit Gentechnik und biologischen Innovationen.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:31:01');
