INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('O6WqE3XTpgJJ', 'Der Wüstenkrieg in Afrika', 'Janusz Piekalkiewicz', 2000, 'Military History', 'history', 'German', '9783828903579', 'Weltbild', 250, 4.3, 13, NULL, NULL, NULL, NULL, '["Afrika - Geschichte"]', NULL, 'https://books.google.com/books?vid=ISBN9783828903579&printsec=frontcover&img=1&zoom=3', 'Eine umfassende Darstellung des nordafrikanischen Konflikts im Zweiten Weltkrieg, die wichtige Schlachten, Strategien und militärische Führungspersönlichkeiten beleuchtet und durch detaillierte Analysen sowie historische Fotografien ergänzt wird. Dieses 1984 erschienene Werk von Janusz Piekalkiewicz bietet eine eingehende Untersuchung der Kriegshandlungen in den Wüstenlandschaften Afrikas.', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:31:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('dJWYij-GbnTv', 'Seekrieg', 'Janusz Piekalkiewicz', 1980, 'Military History', 'history', 'German', '9783512008002', 'Almark Publishing Co.', 352, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8393409-L.jpg', 'Eine umfassende Darstellung der Seekriegsführung im Zweiten Weltkrieg, die Strategien, Schlachten und die Auswirkungen maritimer Auseinandersetzungen detailliert beschreibt und durch unterstützendes Bildmaterial sowie Augenzeugenberichte ergänzt wird.', 'claude-translated-de', '2026-05-14 10:08:11', '2026-05-11 23:09:48', '2026-05-14 13:31:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('6Dr0HH2evyuI', 'Invasion', 'Janusz Piekalkiewicz', 1998, 'History', 'history', 'German', '9783828902794', 'Bechtermünz,', 320, 4.5, 9, NULL, 'Genehmigte Lizenzausgabe', NULL, NULL, NULL, NULL, 'https://m.media-amazon.com/images/I/91P5hHUhj3L.jpg', 'Eine historische Betrachtung der Strategien, Taktiken und Ereignisse bedeutender militärischer Invasionen, die die Vielschichtigkeit und Folgen dieser Operationen im Verlauf der Geschichte darlegt. Das 1974 von Janusz Piekalkiewicz veröffentlichte Werk bietet Einblicke in die Militärgeschichte mit dem Schwerpunkt auf sachlicher Berichterstattung und Analyse.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:31:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('gQNMtwcO74vz', 'Luftkrieg', 'Janusz Piekalkiewicz', 1981, 'Military History', 'history', 'English', '978-0710601433', 'Bertelsmann', 269, 4.2, NULL, NULL, NULL, NULL, NULL, '["Merchant marine"]', NULL, 'https://covers.openlibrary.org/b/id/8414118-L.jpg', 'Eine umfassende Untersuchung der Luftkriegsführung im Zweiten Weltkrieg, die Strategien, bedeutende Schlachten und technische Entwicklungen detailliert beschreibt. Das Buch verbindet historische Analyse mit Augenzeugenberichten und vermittelt ein lebendiges Bild vom Einfluss der Luftmacht auf den Ausgang des Krieges.', 'claude-translated-de', '2026-05-14 10:08:07', '2026-05-11 23:09:48', '2026-05-14 13:31:01');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('oKpgBrrX81Zm', 'Der Präzisions-Luftkrieg gegen Land und Leute', 'Raimund Müller', NULL, 'Non-fiction', 'non-fiction', 'German', NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'Eine umfassende Analyse der Auswirkungen und Strategien des Präzisions-Luftkriegs auf die Zivilbevölkerung und Landschaften, unter Betrachtung sowohl historischer als auch moderner Zusammenhänge.', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:31:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('e7olJ1w1qCSW', 'Der Zweite Weltkrieg', 'R. Oldenbourg', 2022, 'History', 'history', 'German', '9783486588316', 'Walter de Gruyter', 450, NULL, NULL, NULL, NULL, NULL, NULL, '["History"]', NULL, 'https://exlibris.azureedge.net/covers/9783/4865/8831/6/9783486588316xxl.webp', 'Die Neufassung im bewährten Format beleuchtet die Griechische Geschichte vor dem Hellenismus (8. Jh. ‒ 320 v.Chr) in neuartiger Weise: als Teil eines weiträumigen und verflochtenen Geschehens im Mittelmeerraum und am Rand von Großreichen; dabei spielen Mobilität, Migration und Krieg eine zentrale Rolle. Einen weiteren Schwerpunkt bilden die Lust der Griechen an der Politik sowie ihre Kreativität auf diesem Feld. Dabei genießen regionale und lokale Eigenheiten besondere Aufmerksamkeit. Als Alleinstellungsmerkmal bietet der Band einen umfangreichen, mit der gegliederten Bibliographie eng verzahnten Forschungsüberblick. Dieser stellt die Geschichte der Hellenen als Problem vor und orientiert Studierende, aber auch Fachleute benachbarter Disziplinen gründlich und mit weitem Blick über die Kategorien, Konsense und Kontroversen.', 'google_books', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-13 22:49:43');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('xNLuudOROR2L', 'Der Erste Weltkrieg', 'Janusz Piekalkiewicz', 1988, 'History', 'history', 'German', '9783430174817', 'Econ Verlag', 608, 4.7, 37, NULL, NULL, NULL, NULL, '["World War, 1914-1918"]', NULL, 'https://m.media-amazon.com/images/I/71N5Koj6t-L.jpg', 'Umfassende historische Darstellung des Ersten Weltkriegs mit detaillierter Schilderung wichtiger Schlachten, Strategien und politischer Einflüsse, unterstützt durch Fotografien und Berichte aus erster Hand.', 'claude-translated-de', '2026-05-14 10:07:55', '2026-05-11 23:09:48', '2026-05-14 13:31:06');
INSERT OR REPLACE INTO books (node_id, title, author, publication_year, genre, genre_canonical, language, isbn, publisher, page_count, average_rating, rating_count, format, edition, series_name, series_position, categories, purchase_link, cover_image_url, description, description_source, enriched_at, created_at, updated_at) VALUES ('67IhUMr0ENuB', 'Flugzeugbewaffnung', 'Bill Gunston', 1988, 'Aviation History', 'history', 'German', NULL, NULL, 207, NULL, NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'https://covers.openlibrary.org/b/id/8398909-L.jpg', 'Eine Erkundung der Entwicklung und Technik der Flugzeugbewaffnung, die den Werdegang der in der Luftfahrt eingesetzten Waffen und Systeme nachzeichnet – mit Einblicken in historische Meilensteine und technische Fortschritte vom angesehenen Luftfahrtautor Bill Gunston.', 'claude-translated-de', '2026-05-14 10:08:01', '2026-05-11 23:09:48', '2026-05-14 13:31:06');
