INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-_RJbVN6pdtaI', 'Genetik in 30 Sekunden', 'Was ist die DNA und inwieweit bestimmen unsere Gene, wer wir sind? Wie wirkt eine Gentherapie? In den letzten hundert Jahren erlebte die Genetik atemberaubende Fortschritte. In diesem gut verständlichen Handbuch erfahren Sie alles Wesentliche zum Thema – von den Grundlagen bis aktuellen Forschungsergebnissen. Genetik in 30 Sekunden bricht den Fachjargon auf und berichtet von den Meilensteinen der Genetik, begonnen bei den Grundlagen der Zellbiologie bis zu den schier unglaublichen Entwicklungen in der DNA-Sequenzierung und der Genomchirurgie. Fortschritte bei der Stammzellentherapie, beim Klonen von Tieren, maßgeschneiderte Gentherapie und gentechnisch verändertes Getreide haben für Schlagzeilen gesorgt. Haben Sie sich je darüber Gedanken gemacht, was unter all dem zu verstehen ist und was das für unsere Zukunft bedeutet? Experten knacken in 50 Kapiteln den Code und entschlüsseln so die zentralen Begriffe und Ideen zur Genetik auf je einer Doppelseite in Wort und Bild. Dank der informativen Glossare, anschaulichen Grafiken und Biografien der wichtigsten Forscher werden Sie sich schon bald in diesem zentralen Wissenschaftsgebiet der Zukunft zu Hause fühlen. Mehr lesen', 'book', '["jonathan-weitzman", "matthew-weitzman"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-tC_qd23AduIY', 'Swiss Made', 'Eine umfassende Erkundung des wirtschaftlichen Erfolgs der Schweiz: "Swiss Made" von R. James Breiding beleuchtet die Faktoren, die zum weltweiten Ruf des Landes für Innovation, Stabilität und Wohlstand beitragen. Das Buch untersucht eine Vielzahl von Branchen – von Finanzen und Pharmazeutik bis hin zu Technologie und Uhrmacherei – und hebt die kulturellen und historischen Einflüsse hervor, die Schweizer Geschäftsumfeld so einzigartig geprägt haben.', 'book', '["r-james-breiding"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-DJHRCgRo04-T', 'Der Crash kommt', 'Eine Analyse wirtschaftlicher Entwicklungen und eine Warnung vor einer drohenden Finanzkrise: "Der Crash kommt" von Max Otte nimmt die wirtschaftlichen Herausforderungen und Verwerfungen vorweg, die zu einem gravierenden Markteinbruch führen könnten.', 'book', '["max-otte"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-cjiXHYQF4K1Q', 'Crashkurs – Dirk Müller', 'Eine kurzweilige Erkundung der globalen Finanzmärkte: "Crashkurs" von Dirk Müller macht komplexe wirtschaftliche Zusammenhänge für den Leser verständlich. Das 2009 erschienene Buch beleuchtet die Ursachen und Folgen der Finanzkrise und führt den Leser mit praktischen Ratschlägen und Lösungsansätzen durch wirtschaftliche Theorien. Bekannt für seinen klaren und zugänglichen Stil, bietet Müller eine einzigartige Perspektive aus seiner langjährigen Erfahrung im Finanzbereich.', 'book', '["dirk-muller"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-raSRTUkjjLrZ', 'Six Sigma für Dummies', 'Steigern Sie Ihre Effizienz – und erzielen Sie satte Gewinne! Benötigen Sie Hilfe bei der Einführung oder beim Verständnis von Six Sigma? Möchten Sie diese leistungsstarke Problemlösungsmethodik auf Ihr Unternehmen anwenden? Six Sigma ist längst nicht mehr nur großen Konzernen vorbehalten – es eignet sich für jedes Unternehmen, auch Ihres, ganz gleich wie groß oder klein. Dieses praxisorientierte Arbeitsbuch vermittelt Ihnen das Wissen, die Einblicke und die praktischen Übungen, die Sie benötigen, um Six Sigma zu beherrschen und in Ihrem Unternehmen einzusetzen. Als ideale Begleitung zu "Six Sigma für Dummies" – oder jedem anderen Six Sigma-Buch – bietet Ihnen dieses Übungsbuch eine Fülle von Beispielen, Aufgaben und weiteren Werkzeugen, um Six Sigma-Theorie ab sofort in die Praxis umzusetzen. Entdecken Sie: Wie Sie eine Six Sigma-Initiative aufbauen und leiten • Projektausrichtung an Unternehmenszielen und -strategie • Wie Sie Prozessablaufkarten und -modelle erstellen • Diagramm- und Graphendarstellung für Analyse und Auswertung • Methoden zur Berechnung von Sigma-Werten • Wie Sie Variablenbeziehungen quantifizieren', 'book', '["craig-gygi", "bruce-williams", "neil-decarlo"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-E5uENuxFdwOr', 'Statistik mit Excel für Dummies', 'Java für Dummies ist gleichzeitig ein Lehrbuch und ein unverzichtbares Nachschlagewerk für alle Java-Programmierer. Basiswissen zur objektorientierten Programmierung wird genauso vermittelt wie das Prinzip der Wiederverwendbarkeit von Programmbausteinen und allgemeine Grundlagen der Java-Programmierung. Mehr lesen', 'book', '["joseph-schmuller"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-DOU7tony9Fgo', 'Übungsbuch Statistik für Dummies', 'Ein praxisorientierter Leitfaden für Studierende und Berufstätige, der verständliche Erklärungen und Übungen bietet, um statistische Konzepte sicher zu beherrschen.', 'book', '["deborah-j-rumsey"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ocTmmscYYc87', 'Statistik für Dummies', 'Wollen Sie wissen, was mit Ihrem Geld gemacht wird? Dann sind Aktien für Sie die richtige Wahl, denn Sie haben es als Mitunternehmer in der Hand, wem Sie Ihr Geld anvertrauen. Doch was ist eigentlich das Grundprinzip von Aktien? Welche Vorteile haben sie gegenüber anderen Anlageformen? Wie kommen Sie an Aktien und wie ordern Sie geschickt, um Chancen zu nutzenund Risiken überschaubar zu halten? Was beeinflusst Kurse und wie analysieren Sie Kursverläufe, um den richtigen Zeitpunkt für Kauf und Verkauf abzupassen? Wie können Sie mit ganz einfachen Mitteln, Ihre eigene Anlagestrategie entwickeln? Diese und viele weitere Fragen rund um Aktien, Kursverläufe und Börsenpsychologie beantworten Ihnen die beiden Aktienexperten Dr. Christine Bortenlänger und Ulrich Kirstein in diesem Buch, das für die Shortlist des deutschen Finanzbuchpreises nominiert wurde. Damit auch Sie schon bald von Kursen und Dividenden profitieren! Mehr lesen', 'book', '["deborah-j-rumsey"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-fh8gVaj1Wcxo', 'Logik für Dummies', 'Logik ist die Basis der Wissenschaft, aber auch eine Brücke zwischen Wissenschaft und Alltag, denn die Grundlagen sind einfach logisch. Doch so einfach sie auf den ersten Blick scheint, so anspruchsvoll ist sie im Detail. "Logik kompakt für Dummies" führt Sie systematisch und so einfach wie möglich in dieses Teilgebiet von Mathematik und Philosophie ein. Dabei arbeitet Mark Zegarelli mit anschaulichen Beispielen und schafft es so, dieses abstrakte Thema nicht nur verständlich zu erklären, sondern auch Wert und Nutzen der Logik aufzuzeigen. Mehr lesen', 'book', '["mark-zegarelli"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-vT4kARjSbiAc', 'XML für Dummies', 'Schlagzeug und Percussionsinstrumente gelten als leichter Einstieg in die Musik. Doch viele Anfänger stehen schon sehr bald vor dem Problem, die vielfältigen Möglichkeiten des Schlagzeugs zu meistern. Jeff Strong zeigt dem Leser, welche Instrumente zu einem Schlagzeug gehören und welche als Percussionsinstrumente eingesetzt werden. Vom einfachen Rhythmus bis zur lateinamerikanischen Musik, Jazz, Blues und Funk erfährt der Einsteiger alles Grundlegende zu Beats und Tempi. Mehr lesen', 'book', '["lucinda-dykes", "ed-tittel"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-klOfBdC281sw', 'Zeitmanagement für Dummies', '', 'book', '["dirk-mayer"]', '["buch", "genre", "self-help"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_6bc7a4389671', 'Wahrscheinlichkeitsrechnung für Dummies', 'Beim Thema Rechtschreibung zucken viele zusammen. Schon in der Schule waren den meisten Diktate ein Graus. Groß- oder kleinschreiben, auseinander oder zusammen, und wo überhaupt muss ein Komma stehen oder ein Bindestrich? Peinlich, wenn dann später das Bewerbungsschreiben vor Fehlern nur so strotzt, die Examensarbeit inhaltlich zwar top, in Sachen Orthografie aber ein Flop ist oder in der Geschäftskorrespondenz mit wichtigen Kunden unzählige Kommafehler stecken. Ebenfalls unschön, wenn Newsletter und Flyer mehr durch ihre mangelhafte Rechtschreibung als durch ihren Inhalt auffallen. Hinzu kommt die Gewissheit, dass auf das Korrekturprogramm des PC auch kein Verlass ist. Und obendrein noch das Hin und Her um die Rechtschreibung in den letzten Jahren. Wer weiß da überhaupt noch, was Sache ist? Sich auf der Suche nach dem Neuen durch das amtliche Regelwerk zu wühlen, ist ein mühsames Geschäft. Das muss auch gar nicht sein. Dr. Matthias Wermke, der Leiter der Dudenredaktion, verbindet in "Neue deutsche Rechtschreibung für Dummies" die Kompetenz des Dudens mit dem lockeren Stil der Dummies, der Berührungsängste vor trockenen Themen nimmt. Und auf einmal werden die Regeln der neuen deutschen Rechtschreibung sogar Orthografiemuffeln verständlich. Als besonderes Extra enthält der Band ein Wörterbuch mit 47.000 Stichwörtern. Mehr lesen', 'book', '["deborah-rumsey"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_24509925f484', 'Mathe in 30 Sekunden', '"Mathe in 30 Sekunden" von Richard J. Brown ist eine kompakte Erkundung zentraler mathematischer Konzepte, die darauf ausgelegt ist, komplexe Ideen in kurzen, leicht verständlichen Abschnitten zu erläutern. Jedes Thema soll in 30 Sekunden erfassbar sein, was das Buch zu einer zugänglichen Ressource für alle macht, die sich für die Grundlagen der Mathematik interessieren. Das Buch deckt ein breites Themenspektrum ab – von der Geometrie bis zur Analysis – und bietet eine anschauliche Zusammenfassung wesentlicher mathematischer Prinzipien.', 'book', '["richard-j-brown"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_2971171ded6f', 'Newton in 30 Sekunden', 'Die Geschichte vom Apfel, der ihm auf den Kopf fiel, ist weltberühmt, aber was wissen Sie noch über Isaac Newton? Er war ein Multitalent – Physiker, Astronom, Alchemist und Mathematiker –, und die Genialität seines Werkes bahnte zahllosen wissenschaftlichen Entdeckungen den Weg. Frischen Sie Ihre Kenntnisse über sein beeindruckendes Erbe auf und lesen Sie Interessantes über ein Genie, das unsere Welt mitgeformt hat. Newton in 30 Sekunden vermittelt ein einzigartiges Bild eines der größten Genies aller Zeiten und präsentiert seine wichtigsten Ideen und Theorien. Jede Buchseite steckt voller Informationen: von seinen Entdeckungen zu Schwerkraft, Licht, Farben sowie Differential- und Integralrechnung bis zu seiner Zeit als Mitglied des Parlaments. Brian Clegg, Herausgeber, studierte Naturwissenschaften mit Schwerpunkt Experimentalphysik an der Universität Cambridge. Er schrieb für verschiedene Zeitschriften und Zeitungen wie Nature, The Times und The Wall Street Journal und unterrichtete an den Universitäten Oxford und Cambridge sowie der Royal Institution. Er ist Redakteur bei www.popularscience.co.uk und Verfasser zahlreicher Bücher, darunter Quantentheorie in 30 Sekunden. Mehr lesen', 'book', '["brian-clegg"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_b7c33e0b423d', 'Einstein in 30 Sekunden', 'Albert Einstein war ein bahnbrechendes Genie, dessen Ideen und Theorien die Wissenschaft revolutionierten. Mehr als einmal stellte er die Wahrnehmung des Universums auf den Kopf. Mit gerade einmal 26 Jahren sorgte der spätere Nobelpreisträger für wissenschaftlich spektakuläre Erkenntnisse. Albert Einstein war nicht nur ein herausragender Physiker, sondern außerdem ein Kämpfer für die Menschenrechte und ein politischer Aktivist. Einstein, der die wohl berühmteste Formel der modernen Physik E=mc2 formulierte, gilt bis heute als Prototyp des verschrobenen Professors. Einstein in 30 Sekunden eröffnet Ihnen die Gedankenwelt des wohl berühmtesten Physikers unserer Zeit, dessen außergewöhnliches Leben in gleichem Maße wie seine wissenschaftlichen Leistungen beeindruckt. Mit jedem der 50 informativen Kapitel werden sie Albert Einsteins Werk, Leben und Erbe besser verstehen – von der Relativitätstheorie über die Quantenphysik bis zur Kernspaltung. Mehr lesen', 'book', '["brian-clegg"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_ce9e5dcf9490', 'Mythologie in 30 Sekunden', 'Mythologie in 30 Sekunden beleuchtet die wichtigsten Inhalte der bekanntesten klassischen Mythen und erklärt deren verborgene Bedeutung. Das Buch behandelt den Ursprung von Göttern, Helden und Dämonen der alten Griechen und Römer und erläutert dem Leser die grundlegenden Aspekte ihrer Überlieferungen in einer halben Minute auf jeweils zwei Seiten, in rund dreihundert Wörtern und anhand einer Abbildung. Mythologie in 30 Sekunden enthält die Biografien der sieben größten Dichter und Dramatiker des Altertums und verdeutlicht kurz und prägnant den bleibenden Einfluss antiker Mythen. Mehr lesen', 'book', '["robert-a-segal"]', '["buch", "genre", "mythology"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_096439cc1d72', 'GRU – Die Speerspitze', 'Eigentlich hat sich Kommissar Laurenti auf eigenen ruhigen Triester Sommer eingestellt. Doch nach einem merkwürdigen Yacht-Unfall bekommt er es mit Mord, Geldwäsche und Menschenschmuggel zu tun. Darunter leidet nicht nur sein Familienleben ...', 'book', '["viktor-suworow"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_42ee89dbef0f', 'Kampf der Kulturen', 'Ein einflussreiches Werk der Politikwissenschaft, das die Theorie kultureller Konflikte untersucht, die die Weltpolitik nach dem Ende des Kalten Krieges prägen. Im Mittelpunkt steht die These, dass künftige Kriege nicht zwischen Staaten, sondern zwischen Kulturen ausgetragen werden.', 'book', '["samuel-p-huntington"]', '["buch", "genre", "political-science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_0cc2817c4d8f', 'Taktik gegen Terror', 'Rivers, Gayle: Taktik gegen den Terror. Zürich, Wiesbaden. Orell Füssli 1987. Gr-8vo. 213 S. OPb. mit OSchU. Umschlag berieben, druckspurig, leicht bestoßen und stockfleckig, Einband bestoßen, Schnitt (stock-)fleckig, Notiz auf Titel, Seitenkanten altersgemäß gebräunt, sonst in gutem Zustand. Mehr lesen', 'book', '["gayle-rivers"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_0db9e7c3007f', 'US Rangers', 'Eine umfassende Darstellung der Geschichte und der Einsätze der US Rangers, die ihre Entwicklung, bedeutende Missionen und ihren Einfluss auf militärische Taktiken im Detail beleuchtet – verfasst von David Schauer.', 'book', '["david-schauer"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_e4f4f2d38a43', 'Soldaten aus dem Dunkel', 'Eine schaurige Horrorgeschichte von Carl Jacobi: "Soldaten aus dem Dunkel" spinnt ein Netz aus Spannung und übernatürlichen Begegnungen und zieht den Leser in eine Welt, in der die Finsternis böswillige Mächte verbirgt.', 'book', '["carl-jacobi"]', '["buch", "genre", "horror"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_9f184abdafad', 'NSA – Amerikas geheimster Nachrichtendienst', 'Eine eingehende Betrachtung der National Security Agency (NSA), die deren geheime Operationen, Geschichte und Einfluss auf die weltweite Nachrichtendienstarbeit beleuchtet.', 'book', '["james-bamford"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-syn_82cfc37b6a9c', 'Reagan und die geheimen Kriege der CIA', 'Ein investigativer Bericht von Bob Woodward, der geheime CIA-Operationen während der Präsidentschaft Ronald Reagans beleuchtet und die Komplexitäten sowie Kontroversen der amerikanischen Geheimdienstaktivitäten in den 1980er Jahren untersucht.', 'book', '["bob-woodward"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-bb0yOaScc7EE', 'Geheime Nachrichten-Technik', 'Dieser Band erscheint zu Ehren des 100. Geburtstags von Friedrich Hund. Er bietet einen modernen Überblick über Materie bei hohen Dichten und Drücken in der Astrophysik – von Hunds frühen Beiträgen bis hin zu heutigen Konzepten. Der Zusammenhang zwischen der Zustandsgleichung und der Struktur kompakter kosmischer Objekte wird erörtert; zwei zentrale Beiträge behandeln die Zustandsgleichung baryonischer Materie bei nuklearen Dichten sowie die numerische Lösung der allgemein-relativistischen Feldgleichungen für nicht rotierende und schnell rotierende Neutronensterne. In einem abschließenden Kapitel wird der aktuelle Stand der Asteroseismologie als Werkzeug zur Erforschung des Inneren kosmischer Objekte vorgestellt, indem beobachtete freie Schwingungen der Erde, der Sonne und weißer Zwergsterne analysiert werden.', 'book', '["otto-schreier"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-fOcjD2CZC5jp', 'Nuclear Battlefields', 'Eine eingehende Untersuchung der weltweiten nuklearen Waffeninfrastruktur während des Kalten Krieges, die Standorte, Strategien und Auswirkungen nuklearer Arsenale und Schlachtfelder rund um den Globus beleuchtet.', 'book', '["william-m-arkin", "richard-w-fieldhouse"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-IB83F_KcAMLt', 'Credit Risk Modeling using Excel and VBA', 'Es ist weit verbreitet, die Unzulänglichkeit von Kreditrisikomodellen dafür verantwortlich zu machen, dass die Finanzkrise viele Marktteilnehmer unvorbereitet traf. Bei näherer Betrachtung zeigt sich jedoch häufig, dass die Marktteilnehmer die Modelle nicht richtig verstanden oder angewendet haben. Die jüngsten Ereignisse stellen daher die traditionelle Kreditrisikomodellierung, wie sie in der ersten Auflage des Buches beschrieben wurde, nicht grundsätzlich in Frage. Eine zweite Auflage ist dennoch zeitgemäß, da die erste Auflage jene Instrumente, die in der Krise eine zentrale Rolle spielten (CDS und CDO), nur kurz behandelte. Neben einer ausführlicheren Darstellung dieser Instrumente konzentriert sich das Buch auf Modellierungsaspekte, die in der Finanzkrise besonders relevant waren (z. B. Schätzfehler), und veranschaulicht den Nutzen der Kreditrisikomodellierung anhand von Fallstudien. Dieses Buch bietet Praktikern und Studierenden eine anschauliche, praxisorientierte Einführung in die moderne Kreditrisikomodellierung. Jedes Kapitel beginnt mit einer Erläuterung der Methodik, bevor die Autoren den Leser Schritt für Schritt durch die Umsetzung der Verfahren in Excel und VBA führen. Der Schwerpunkt liegt auf Fragen des Risikomanagements; behandelt werden die Schätzung von Ausfallwahrscheinlichkeiten (Scoring, Strukturmodelle und Übergangsmatrizen), Korrelations- und Portfolioanalyse, Validierung sowie Kreditausfallswaps und strukturierte Finanzierungen. Zum Buch gehört eine begleitende Website, https://creditriskmodeling.wordpress.com/, die eigens für diese zweite Auflage aktualisiert wurde und Folien sowie Übungsaufgaben für Dozenten enthält.', 'book', '["gunter-loffler", "peter-n-posch"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xoKYLPLooJ1Y', 'Speed Reading', 'Vom Bestsellerautor von The Mind Map Book und Use Both Sides of Your Brain – steigern Sie Ihre Lesegeschwindigkeit, Ihr Textverständnis und Ihre Merkfähigkeit dramatisch. Tony Buzan, weltbekannter Experte auf dem Gebiet des Gehirns und Erfinder des Mind Mappings, hat mit den in Speed Reading vorgestellten Methoden internationale Anerkennung erlangt. Das Buch enthält nicht nur die bewährten Grundlagen des Schnelllesens, sondern ist das erste Werk zu diesem Thema, das die neuesten Erkenntnisse über das erstaunliche Potenzial und die komplexen Funktionsweisen des menschlichen Gehirns einbezieht. In einem leicht verständlichen, direkten Stil bietet dieser Klassiker: • Neue Ansätze zum Lesen, Lernen, zur Konzentration und Wissensaneignung • Selbsttests, die das Interesse an verschiedenen Wissensgebieten anregen • Die Möglichkeit, Ihre Lese- und Verständnisleistung zu messen und systematisch zu verbessern. Die überarbeitete dritte Auflage bietet modernste Techniken zur Steigerung von Lesegeschwindigkeit und Textverständnis – vom einfachsten bis zum anspruchsvollsten Niveau.', 'book', '["tony-buzan"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-rNCGaoOV0CWb', 'MasterClass: Tony Buzan', 'Ein umfassender Leitfaden von Tony Buzan zur Steigerung geistiger Fähigkeiten und zur Verbesserung von Lerntechniken, mit Schwerpunkt auf Gedächtnisverbesserung, schnellem Lesen und Mind-Mapping-Strategien.', 'book', '["tony-buzan"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-YdjbaGjCMQGj', 'Exchange Traded Funds und Anlagestrategien: Das ETF-Praxisbuch', 'Exchange Traded Funds (ETFs) sind in den vergangenen Jahren zu einem wichtigen Baustein vieler Anlagedepots geworden. Dank breiter Risikodiversifikation, tiefen Kosten und einfacher Handelbarkeit werden sie nicht mehr nur von Privatanlegern eingesetzt. Auch professionelle Vermögensverwalter und institutionelle Anleger greifen vermehrt auf ETFs zurück. Aber wie funktionieren ETFs genau und welche Chancen und Risiken bieten sie? Welche Märkte decken sie ab? Auf was ist bei der ETF- bzw. Index-Wahl beim Investieren in Aktien, Anleihen, Rohstoffe, Hedge Funds usw. zu achten? Diese Themen sowie konkrete Einsatzmöglichkeiten von ETFs in Anlagestrategien und verschiedene Tipps bei der Umsetzung von Investitionsentscheidungen stehen im Mittelpunkt dieses Buches. Für das Verständnis von praktischen Herausforderungen bedarf es theoretischer Grundlagen. Auch diese kommen nicht zu kurz: Von der Theorie der Risikodiversifikation, den Optimierungsmethoden von Portfolios bis zu den Tücken des Tracking Errors. Die ausgewählten Themen sollen dem Leser eine kritische Auseinandersetzung mit häufig gestellten Fragen aus der Investmentwelt ermöglichen und Hilfestellung leisten. Nicht zu kurz kommen die Vorstellung der grössten ETF-Anbieter, Unterschiede zwischen den bekannten US-Aktienindizes wie S&P 500, Dow Jones und Nasdaq sowie viele weitere Fragestellungen aus der Praxis. Das Buch ist von Praktikern für Praktiker geschrieben und soll allen, die mehr rund um das Thema ETFs und Anlagestrategien wissen wollen, den Überblick erleichtern. Das vorliegende Buch eignet sich insbesondere für: Interessierte Privatanleger, Kundenberater, Portfoliomanager, Studenten und Journalisten. 28.06.2012 / NZZ: "Mit «Exchange Traded Funds und Anlagestrategien» geben Daniel Niedermayer und Marcel Wagner einen Leitfaden, um ETF zu verstehen und richtig einzusetzen." 20.06.2012 / FuW: "Ein neues, umfassendes Werk über Exchange Traded Funds liegt vor." Mehr lesen', 'book', '["norbert-niedermayer", "christian-wagner"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kxnAxRC41Buk', 'Managing Credit Risk (Second Edition)', 'Managing Credit Risk, zweite Auflage, beginnt mit einer ausführlichen Erörterung der heutigen globalen Kreditmärkte – von der Bedeutung von Hedgefonds als wichtige Akteure bis hin zum wachsenden Einfluss von Ratingagenturen. Nach einem soliden Verständnis dieser Zusammenhänge werden einige der wirksamsten Instrumente, Techniken und Vehikel des Kreditrisikomanagements vorgestellt, die derzeit verfügbar sind. Wer mit den ständigen Veränderungen in der Welt des Kreditrisikomanagements Schritt halten muss, findet in diesem Buch die nötige Orientierung.', 'book', '["john-caouette", "edward-i-altman", "paul-narayanan", "nimmo"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kx6XOx0dNO9A', 'Introduction to Swiss Law', 'Ein umfassender Leitfaden zum Rechtssystem der Schweiz, der wesentliche Aspekte des schweizerischen Rechts für Studierende, Praktiker und alle behandelt, die das Rechtssystem des Landes verstehen möchten.', 'book', '["f-dessemontet", "t-ansay"]', '["buch", "genre", "legal"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-CJoguOFxp7Ir', 'Das schweizerische Bankgeschäft', 'Eine Darstellung des schweizerischen Bankwesens, die seine Geschichte, seinen Betrieb und seine Rolle im globalen Finanzmarkt beleuchtet.', 'book', '["urs-emch", "hugo-renz", "reto-arpagaus"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-VMht1W7sF133', 'Operational Risk', 'Ein umfassendes Werk, das die Herausforderungen und Rahmenbedingungen beim Management operationeller Risiken in Finanzinstituten untersucht, mit Schwerpunkt auf Messtechniken, regulatorischen Anforderungen und bewährten Verfahren zur Risikominderung.', 'book', '["carol-alexander"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-9tZ0Ed7kAv7r', 'Market Risk Analysis, Vol. I: Quantitative Methods in Finance', 'Verfasst von der führenden Wissenschaftlerin im Bereich Marktrisiko, Professorin Carol Alexander, ist Quantitative Methods in Finance der erste Band des vierbändigen Werks Market Risk Analysis. Von den Grundlagen ausgehend, hilft dieses Buch den Lesern, den ersten Schritt auf dem Weg zu einer fundierten Qualifikation als Finanzrisikomanager oder Vermögensverwalter zu machen – Berufsfelder, die derzeit stark nachgefragt werden. Das Buch richtet sich an aufgeschlossene Leser mit grundlegenden Mathematikkenntnissen auf Abiturniveau oder an Personen mit einem Hochschulabschluss in Mathematik, Physik oder Ingenieurwissenschaften; Vorkenntnisse in Finanzen sind nicht erforderlich. Der Schwerpunkt liegt auf dem Verständnis von Konzepten und nicht auf mathematischer Strenge, sodass das Buch einen schnellen Einstieg in die Finanzanalyse für Leser mit quantitativem Hintergrund bietet und dabei jene mathematischen Bereiche hervorhebt, die für die Lösung von Problemen im Finanz- und Vermögensrisikomanagement besonders relevant sind. Ein besonderes Merkmal dieses Buches ist die gleichzeitige Behandlung von zeitkontinuierlicher und zeitdiskreter Finanzmathematik: Quantitative Methods in Finance beschränkt sich damit nicht nur auf die Anwendung der Mathematik in der Finanzwelt, sondern erläutert in didaktisch vorbildlicher Weise, wie diese beiden Disziplinen zusammenwirken – ein umfassender, gut zugänglicher Leitfaden, der Lesern die Werkzeuge an die Hand gibt, ihr Wissen sofort anzuwenden. Der gesamte vierbändige Satz Market Risk Analysis veranschaulicht nahezu jeden Begriff und jede Formel anhand eines praktischen numerischen Beispiels oder einer ausführlicheren empirischen Fallstudie. Über alle vier Bände hinweg finden sich rund 300 numerische und empirische Beispiele, 400 Grafiken und Abbildungen sowie 30 Fallstudien, von denen viele in interaktiven Excel-Tabellen auf der beiliegenden CD-ROM enthalten sind. Empirische Beispiele und Fallstudien speziell für diesen Band umfassen: Hauptkomponentenanalyse europäischer Aktienindizes; Kalibrierung der Student-t-Verteilung mittels Maximum-Likelihood-Methode; Orthogonale Regression und Schätzung von Aktienfaktormodellen; Simulationen der geometrischen Brownschen Bewegung und korrelierter Student-t-Variablen; Bewertung europäischer und amerikanischer Optionen mit Binomialbäumen sowie europäischer Optionen mit der Black-Scholes-Merton-Formel; Kubische Spline-Anpassung von Zinskurven und impliziten Volatilitäten; Lösung des Markowitz-Problems ohne Leerverkäufe und mit weiteren Nebenbedingungen; Berechnung risikoadjustierter Performancekennzahlen, darunter das verallgemeinerte Sharpe-Verhältnis sowie Omega- und Kappa-Indizes.', 'book', '["carol-alexander"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-icxsCAz7jkI2', 'Market Risk Analysis, Vol. II: Practical Financial Econometrics', 'Verfasst von der führenden Wissenschaftlerin im Bereich Marktrisiko, Professorin Carol Alexander, ist Quantitative Methods in Finance der erste Band des vierbändigen Werks Market Risk Analysis. Von den Grundlagen ausgehend, hilft dieses Buch den Lesern, den ersten Schritt auf dem Weg zu einer fundierten Qualifikation als Finanzrisikomanager oder Vermögensverwalter zu machen – Berufsfelder, die derzeit stark nachgefragt werden. Das Buch richtet sich an aufgeschlossene Leser mit grundlegenden Mathematikkenntnissen auf Abiturniveau oder an Personen mit einem Hochschulabschluss in Mathematik, Physik oder Ingenieurwissenschaften; Vorkenntnisse in Finanzen sind nicht erforderlich. Der Schwerpunkt liegt auf dem Verständnis von Konzepten und nicht auf mathematischer Strenge, sodass das Buch einen schnellen Einstieg in die Finanzanalyse für Leser mit quantitativem Hintergrund bietet und dabei jene mathematischen Bereiche hervorhebt, die für die Lösung von Problemen im Finanz- und Vermögensrisikomanagement besonders relevant sind. Ein besonderes Merkmal dieses Buches ist die gleichzeitige Behandlung von zeitkontinuierlicher und zeitdiskreter Finanzmathematik: Quantitative Methods in Finance beschränkt sich damit nicht nur auf die Anwendung der Mathematik in der Finanzwelt, sondern erläutert in didaktisch vorbildlicher Weise, wie diese beiden Disziplinen zusammenwirken – ein umfassender, gut zugänglicher Leitfaden, der Lesern die Werkzeuge an die Hand gibt, ihr Wissen sofort anzuwenden. Der gesamte vierbändige Satz Market Risk Analysis veranschaulicht nahezu jeden Begriff und jede Formel anhand eines praktischen numerischen Beispiels oder einer ausführlicheren empirischen Fallstudie. Über alle vier Bände hinweg finden sich rund 300 numerische und empirische Beispiele, 400 Grafiken und Abbildungen sowie 30 Fallstudien, von denen viele in interaktiven Excel-Tabellen auf der beiliegenden CD-ROM enthalten sind. Empirische Beispiele und Fallstudien speziell für diesen Band umfassen: Hauptkomponentenanalyse europäischer Aktienindizes; Kalibrierung der Student-t-Verteilung mittels Maximum-Likelihood-Methode; Orthogonale Regression und Schätzung von Aktienfaktormodellen; Simulationen der geometrischen Brownschen Bewegung und korrelierter Student-t-Variablen; Bewertung europäischer und amerikanischer Optionen mit Binomialbäumen sowie europäischer Optionen mit der Black-Scholes-Merton-Formel; Kubische Spline-Anpassung von Zinskurven und impliziten Volatilitäten; Lösung des Markowitz-Problems ohne Leerverkäufe und mit weiteren Nebenbedingungen; Berechnung risikoadjustierter Performancekennzahlen, darunter das verallgemeinerte Sharpe-Verhältnis sowie Omega- und Kappa-Indizes.', 'book', '["carol-alexander"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-0ILKr91IJxYr', 'Market Risk Analysis, Vol. IV: Value-at-Risk Models', 'Verfasst von der führenden Wissenschaftlerin im Bereich Marktrisiko, Professorin Carol Alexander, ist Practical Financial Econometrics der zweite Band des vierbändigen Werks Market Risk Analysis. Er führt in die ökonometrischen Methoden ein, die in der Finanzwelt gängig sind – mit einer kritischen und gezielten Darstellung, die jene Bereiche der Ökonometrie besonders betont, wie etwa GARCH, Kointegration und Kopulas, die für die Lösung von Problemen in der Marktrisiko-Analyse unerlässlich sind. Das Buch deckt den Stoff eines einsemestrigen Masterkurses in angewandter Finanzökonometrie in didaktisch vorbildlicher Weise ab: Jedes neu eingeführte Konzept wird unmittelbar anhand eines empirischen Beispiels veranschaulicht, das wann immer möglich durch eine Excel-Tabelle illustriert wird. Der gesamte vierbändige Satz Market Risk Analysis veranschaulicht nahezu jeden Begriff und jede Formel anhand eines praktischen numerischen Beispiels oder einer ausführlicheren empirischen Fallstudie. Über alle vier Bände hinweg finden sich rund 300 numerische und empirische Beispiele, 400 Grafiken und Abbildungen sowie 30 Fallstudien, von denen viele in interaktiven Excel-Tabellen auf der beiliegenden CD-ROM enthalten sind. Empirische Beispiele und Fallstudien speziell für diesen Band umfassen: Faktoranalyse mit orthogonalen Regressionen und unter Verwendung von Hauptkomponentenfaktoren; Schätzung symmetrischer und asymmetrischer GARCH- und E-GARCH-Parameter für Normal- und Student-t-Verteilungen; Normal-, Student-t-, Gumbel-, Clayton- und Normalgemisch-Kopuladichten sowie Simulationen aus diesen Kopulas mit Anwendung auf Value-at-Risk und Portfoliooptimierung; Hauptkomponentenanalyse von Zinskurven mit Anwendungen auf Portfolio-Immunisierung und Asset-Liability-Management; Simulation von Normalgemisch- und Markov-Switching-GARCH-Renditen; Kointegrationsbasiertes Index-Tracking und Pairs-Trading mit Fehlerkorrektur- und Impulsantwortmodellierung; Markov-Switching-Regressionsmodelle (EViews-Code); GARCH-Terminstrukturprognosen mit Volatilitäts-Targeting; Nichtlineare Quantilregressionen mit Anwendungen auf das Hedging.', 'book', '["carol-alexander"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-LOAvF1yD8ewv', 'Kursbuch Gesundheit', 'Ein umfassender Ratgeber zu Gesundheitsthemen, der Einblicke in die Erhaltung und Förderung des Wohlbefindens bietet und sich an alle richtet, die ihr Wissen rund um Gesundheit und Wohlbefinden erweitern möchten.', 'book', '[]', '["buch", "genre", "health"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ep9EIV_oOCNU', 'Das Buch vom guten Benehmen', 'Ein umfassender Ratgeber zu Manieren und Etikette. "Das Buch vom guten Benehmen" von Jacob Ernst von Buggenhagen vermittelt Einblicke in die gesellschaftlichen Normen und das angemessene Verhalten des frühen 20. Jahrhunderts und bietet zeitlose Ratschläge, wie man in verschiedenen sozialen Situationen Anstand und Höflichkeit wahrt.', 'book', '["jacob-ernst-von-buggenhagen"]', '["buch", "genre", "reference"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-7LH7qLEtFdZB', 'Archäologie', 'Ein Sachbuch, das das Feld der Archäologie beleuchtet und Methoden, Entdeckungen sowie historische Erkenntnisse behandelt. Der Autor ist unbekannt.', 'book', '["wolfram-schurer"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-prCM2quNmjbC', 'Eselsbrücken (Duden)', 'Eselsbrücken sind kluge Sätze, die handfeste Informationen unvergesslich machen - und das seit Generationen! Wie erinnern wir uns an das "Gründungsjahr Roms" und an die "Reihenfolge der Planeten" oder dass man "nämlich ohne h schreibt" und dass "afrikanische Elefanten lange Ohren haben"? Diese Sammlung von mehr als 200 altbekannten und weniger bekannten Eselsbrücken samt eingängigen Erläuterungen bietet einen Fundus an Allgemeinbildung aus den Themengebieten Geschichte, Sprache, Geografie, Naturwissenschaften, Mathematik, Kunst und Alltagswissen. Mit ausführlichem Register zum schnellen Nachschlagen. Mehr lesen', 'book', '["wolfgang-riedel"]', '["buch", "genre", "reference"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-i9Vxtab_548A', 'Chartmuster – simplified', 'Nach über 20 Jahren Marktanalyse hat Ed Downs die sieben besten Chartformationen für jede Art der Finanzlage entdeckt. Sowohl Trader als auch Investoren können mit diesen Chartformationen das Maximum an der Börse herausholen. Mehr lesen', 'book', '["ed-downs"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-pbulTk6fZIUD', 'Trick 77 – Die beliebtesten Hörtipps aus der Sendung «Espresso» von DRS 1', 'Eine Sammlung beliebter Hörtipps aus der Radiosendung «Espresso» auf DRS 1, die praktische Ratschläge und nützliche Hinweise zu einer Vielzahl alltäglicher Themen bietet.', 'book', '["krispin-zimmermann"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-DWNGNZ_6e99H', 'Trick 77 – 75 neue Hörtipps aus der Sendung «Espresso» von DRS 1', 'Eine Sammlung von 75 neuen Hörtipps aus der Sendung «Espresso» auf DRS 1, die den Zuhörern informative und kurzweilige Beiträge zu den verschiedensten Themen liefert.', 'book', '["krispin-zimmermann"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-hnkX_PtrznDy', 'Orientierungslaufen', 'Ein umfassender Ratgeber zum Sport des Orientierungslaufens, der Techniken, Navigationsfähigkeiten und die Ausrüstung für Wettkampfstrecken behandelt.', 'book', '["wolfram-schurer"]', '["buch", "genre", "sports"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Rj3bmInoyjN2', 'Charttechnik – simplified', 'An der Technischen Analyse kommt heute kein seriöser Trader oder Investor mehr vorbei. Das wichtigste Instrument dabei: die Charttechnik. Ein Chart ist hierbei ein Diagramm, das den Kursverlauf des Wertpapiers über einen bestimmten Zeitraum darstellt. In diesem simplifi ed- Buch erklärt Ihnen John Murphy leicht verständlich und umfassend alle Grundlagen, um an den Finanzmärkten erfolgreich zu traden. Charts sind das Herz der Technischen Analyse. Er führt Sie umfassend in die Welt der Chartdiagramme ein, von Widerstandslinien bis V-Bottom, von Balkencharts bis Candlesticks. Das leicht verständlich und umfassend Einsteiger-Buch für alle, die ihre Anlageerfolge entscheidend verbessern wollen. Mehr lesen', 'book', '["john-j-murphy"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-zTIAqZJoeXyH', 'Technische Analyse – simplified', 'Ein umfassender Leitfaden zum Verständnis und zur Anwendung der technischen Analyse an Finanzmärkten, verfasst von Pierre M. Daeubner, mit dem Ziel, komplexe Konzepte für Leser verständlich zu machen, die praktische Einblicke suchen.', 'book', '["pierre-m-daeubner"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-g2JBSQMPvRJ6', 'GRASP – The Solution', 'Innovation unterscheidet einen Anführer von einem Nachfolger – wer möchten Sie sein? GRASP The Solution ist ein erfrischend pragmatischer und klar formulierter Leitfaden für kreative Entscheidungsfindung und Problemlösung. Wer schon immer dachte, Kreativität sei nichts als heiße Luft ohne greifbaren Inhalt, wird nach diesem Buch anders denken.
Wie man die besten Antworten auf alltägliche Herausforderungen findet
Fällt es Ihnen schwer, neue und innovative Ideen zu entwickeln? Haben Sie die Idee, können sie aber nicht umsetzen? Suchen Sie verzweifelt nach den richtigen Antworten? Sind Sie frustriert von gescheiterten Gruppen-Brainstorming-Sitzungen?
Chris Griffiths (Leiter von ThinkBuzan, der Organisation hinter dem Mind Mapping – dem Denkinstrument, das weltweit von Millionen genutzt wird) fordert Sie auf, loszulassen, was Ihre Kreativität hemmt. In nur vier klaren Schritten zeigt er Ihnen, wie Sie mutige, frische Ideen und Lösungen auf systematische Weise entfalten können, um jede Herausforderung mit Innovationskraft zu meistern.
Stimmen zum Buch
«Chris zeigt mit Klarheit und Überzeugungskraft, dass kreatives Denken kein Zaubertrick ist, sondern ein Prozess, der erlernt, entwickelt und – was am wichtigsten ist – auf die Herausforderungen angewendet werden kann, denen wir alle begegnen, ob beruflich oder persönlich. Eine ausgezeichnete Ressource. Greifen Sie zu.» Tim Hurson, Autor von ''Think Better: An Innovator''s Guide to Productive Thinking''
«Chris und seine Arbeit haben mein Leben verändert und weltweit bereits das Leben von Millionen Menschen zum Besseren gewandelt. Seine Arbeit ist dabei, dasselbe für SIE zu tun!» Tony Buzan, Bestsellerautor mit millionenfacher Auflage und Erfinder des Mind Mappings
«Ein Muss mit präzisen Techniken, um Ihren Denkprozess und Ihre Produktivität zu steigern. Ich würde dieses Buch jedem empfehlen, der bereit ist, voranzukommen und Herausforderungen anders zu betrachten. Wenn Sie Ihre Probleme in praktische Lösungen verwandeln möchten, wird dieses Buch Ihnen definitiv helfen.» Philippe Packu, Business-Analyst, Sony
«Unternehmen proklamieren die Notwendigkeit, ''intelligenter zu arbeiten'' – Chris Griffiths liefert einen Fahrplan, wie das gelingt.» Bob Urichuck, Autor von ''Disciplined For Life'' und ''You Are the Author of Your Future''
«Dieses Buch bietet neue Werkzeuge und Techniken rund um Kreativität und Innovation für Ihren persönlichen, beruflichen und gesellschaftlichen Erfolg. Es hilft Ihnen, anders zu denken. Lesen Sie es und werden Sie ein Wegbereiter!» Professor M.S. Rao, internationaler Führungsexperte und Autor von ''Success Sutras Lead Your Life Successfully''
«Wenn alle Chris'' Buch lesen und seine Vorschläge täglich umsetzen würden, kämen wir alle schneller auf den Punkt und gewännen den kostbarsten Schatz: Zeit!» Oriol Marimon-Clos, Geschäftsführer, Ideas Angels
«Chris hat meine Art zu denken und Lösungen zu entwickeln grundlegend verändert und eine kreative Stimme in mir geweckt, von der ich nicht wusste, dass sie existiert.» Ed Allen, Konteradmiral der US Navy (a.D.), Executive Business Coach, Executive Success Group
«Ich habe viele Ideen gewonnen und einen echten Wandel in meinem Denken erlebt.» John Brooker, Yes! And...
«Ich halte Chris Griffiths für eines der großen Talente, die in den kommenden Jahren aufblühen werden.» Ron Kaufman, Bestsellerautor von ''UP Your Service!''
«Chris fordert Menschen heraus, mit ''alten Gewohnheiten'' zu brechen und kreative Ideen für neue Wege zu embracen.» Brenton Nicholls, Direktor, Impact Unlimited
«Chris ist eine seltene Kombination aus Unternehmer und Wirtschaftsexperte: Er beherrscht die gesamte Theorie vollständig, ohne sich in ihr zu verlieren. Stattdessen macht er sie für die reale Welt nutzbar. Dieses Buch ist vielleicht der beste Beweis dafür – es hilft Ihnen nicht nur, bessere Ideen zu entwickeln, sondern sie (und das ist das Entscheidende) auch zum Leben zu erwecken und Wirklichkeit werden zu lassen!» Liam Hu', 'book', '["chris-griffiths", "melina-costi"]', '["buch", "genre", "business"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xuUANABLfNWU', 'Mind Maps for Business', 'Das heutige Informationsumfeld erfordert von uns allen, Zeit zu sparen, die Effizienz zu steigern und kreativer zu denken. Mind Mapping ist ein unverzichtbares Geschäftswerkzeug, das Sie Ihrem geistigen Rüstzeug hinzufügen können. Dieser Infoline-Band führt Sie in das Konzept des Mind Mappings ein. Sie lernen, wie man Mind Maps liest und erstellt, Mind Maps für gängige Geschäfts- und Trainingsprozesse einsetzt sowie Kreativität und Leistungsfähigkeit durch den Einsatz von Mind Maps steigert. Trainer können Mind Maps im Besonderen nutzen, um geplante Kurse oder Programme zu skizzieren, einen Geschäftsfall für neue Projekte oder Finanzierungen darzustellen, Inhalte von Trainingsprogrammen zu strukturieren, Ideen während Besprechungen und Trainingseinheiten zu entwickeln sowie Verbindungen zwischen Geschäftsanforderungen und Entwicklungsmaßnahmen herzustellen.', 'book', '["tony-buzan", "chris-griffiths"]', '["buch", "genre", "business"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-1LWkubeJ76H8', 'Raumfahrt Lexikon', 'Ein umfassendes Nachschlagewerk von Stanislav Stanek, das verschiedene Aspekte der Raumfahrt, Technologie und Geschichte ausführlich behandelt. ...', 'book', '["stanislav-stanek"]', '["buch", "genre", "reference"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-MdWx9_cQh8Qx', 'Planeten Lexikon', 'Ein informativer Leitfaden zu den Planeten, der ausführliche Beschreibungen, historischen Kontext und wissenschaftliche Erkenntnisse bietet, verfasst von Richard Stanek.', 'book', '["bruno-stanek"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-tUzebbCnrDES', 'Astronomie', 'Eine Erkundung astronomischer Konzepte und Phänomene, verfasst von Fachleuten auf diesem Gebiet, die Einblicke in die Geheimnisse des Universums und die wissenschaftlichen Grundprinzipien bietet, die es beherrschen.', 'book', '["karttunen", "kroger", "oja", "donner", "poutanen"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-JBDr_OCxNTZk', 'Die Kunst der Überlegenheit', 'Das Wesen des Führens zu verstehen und starke Führungsqualitäten herauszubilden, ist eine der wichtigsten Aufgabe heutiger Gesellschaften. Aber bereits in frühen Zeiten galt es als größte Herausforderung, Führungsqualitäten zu beweisen, vor allem dann, wenn die Bedingungen extrem schwierig waren. In diesem Zusammenhang kommt zwei Männern aus dem alten China ganz besondere Bedeutung zu: dem berühmten Feldherrn Sun Tzu und dem großen Philosophen Konfuzius. Kombiniert man ihre beiden Konzepte des Führens, so ergibt das ein System, das auch unter den schwierigsten Bedingungen funktioniert. Diesen Ansatz greift der Autor auf und überträgt die herausragenden militärischen und politischen Ideen direkt auf moderne Wirtschaftssituationen. Er bringt die philosophischen Visionen Sun Tzus und Konfuzius'' auf den Punkt und schafft so eine "Straßenkarte zum Erfolg". Mehr lesen', 'book', '["donald-g-krause"]', '["buch", "genre", "business"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-N7WHvMmE5nwN', 'Spieltheorie für Führungskräfte', 'Die Spieltheorie ist spätestens seit der Verleihung des Nobelpreises für Wirtschaftswissenschaften an den Deutschen Reinhard Selten auch hierzulande ein Begriff. Ohne mathematische Formeln und wissenschaftlichen Fachjargon erklärt dieses erste originär deutschsprachige Buch zur hochaktuellen Thematik anhand von vielen realen Beispielen, wie die Spieltheorie funktioniert, was sie leisten und was sie nicht leisten kann. Die Faktoren -Spieler-, -Strategie-, -Information-, -Wertschöpfung- und -Spielregeln- bestimmen das Spiel. Sie sind die Hebel, an denen angesetzt werden muss, um Spiele nach eigenen Zielen zu gestalten und zu verändern. Die Spiele sind Szenarien. Erst die gedankliche Disziplin, in der Spieltheorie gibt dann den (Management-)Szenarien die notwendige klare, auf wenige strategisch relevante Kernpunkte reduzierte Struktur. Durch den (Gedanken-)Rahmen der Spiele wissen die Spieler, was sie tun soll(t)en - und vor allem, wie sie es tun müssen, um ihre Ziele zu realisieren . Die Spieltheorie zeigt, wie man in konkreten Entscheidungssituationen die richtigen Entscheidungen finden kann, neue Sichtweisen von Situationen gewinnt und -Lösungen- in die Praxis umsetzt. Die anschaulichen Beispiele stammen zum großen Teil aus dem militärischen Bereich (Hannibal, Napoleon, Erster und Zweiter Weltkrieg, Golfkrieg), aber auch aus dem zivilen Leben (Krankenhaus-Management, Bank- und Börsengeschehen). Inzwischen haben auch amerikanische Business Consultants den Wert der Spieltheorie als Strategiepraktik für nichtmilitärische Zwecke erkannt. Für die erfolgreiche Umsetzung spieltheoretischer (Denk-)Logik in die Management-Praxis ist der Harvard-Management-Professor Michael Porter ein weltberühmter Zeitzeuge. Viele Regierungen und verschiedenste Organisationen in der ganzen Welt ziehen Spieltheoretiker als Berater heran. Noch dazu ist dieses bahnbrechende Buch auch eine Tour d-horizon durch die Geschichte des strategischen Denkens. Mehr lesen', 'book', '["volker-bieta", "wilfried-siebe"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Pjsb7xybsDTu', 'Elon Musk: Tesla, SpaceX, and the Quest for a Fantastic Future', 'Eine Biografie, die das Leben und die Leistungen von Elon Musk beleuchtet, mit einem Schwerpunkt auf seinen Unternehmungen bei Tesla, SpaceX und anderen bahnbrechenden Projekten. Sie gewährt Einblicke in seinen Antrieb, seinen Erfindergeist und seinen Einfluss auf die Zukunft der Technologie.', 'book', '["ashlee-vance"]', '["buch", "genre", "biography"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-nmKezVUlnOi_', 'Gewinnen mit Börsenzyklen', 'Gewinnen mit Börsenzyklen Jeder Anleger kennt Jahresanfangs-Rallyes, Jahresend-Rallyes und die Sommerkorrekturen der Börsen. Diese Börsenphasen entstehen aber nicht zufällig, sondern wiederholen sich permanent, folgen also einem zyklischen Muster. Gewinnen mit Börsenzyklen zeigt anhand der kompletten Kurshistorie von Dax (seit 1959) und Dow Jones (seit 1896) den typischen zyklischen Kursverlauf der Börsen. Dabei wird eine detaillierte Untersuchung aller Jahres-Zyklen, Wahl-Zyklen, Zyklen der 4-Jahres-Tiefs, unterjährigen Zyklen und Jahrzehnt-Zyklen vorgenommen, so dass Gesamtverlauf und damit Start und Ende der entsprechenden Zyklen klar und nachvollziehbar werden. In insgesamt 31 Zyklen-Portfolios werden darauf basierende Anlagemodelle vorgestellt, die fast ohne Aufwand und mit einem deutlich reduzierten Risiko eine massive Outperformance von Dax und Dow Jones ermöglichen. Gegenüber einer Buy-and-Hold-Strategie lassen die Gewinne unter zu Hilfenahme von Zyklen sogar um das bis zu 33-fache steigern! Daneben zeigt eine ausführliche Besprechung der Demographie-Zyklen und der Technologie-Zyklen, warum die nächsten Jahre außergewöhnliche Börsenperspektiven eröffnen. Als Zusammenfassung aller behandelten Zyklen ergeben sich folgende Prognosen: - Dax und Dow Jones haben die Tiefs des Jahrzehnts schon hinter sich! - Die laufende Hausse wird sich bis 2009/2010 fortsetzen! - Das Mindestkursziel sind 10.000 für den Dax und 26.000/29.000 für den Dow Jones! - Vielleicht entsteht aber sogar eine noch viel größere Börsenblase als 1999/2000. Das würde bis Ende des Jahrzehnts zu noch deutlich höheren Notierungen führen, worauf ab 2010 aber eine Extrem-Baisse folgen sollte! Das Buch erklärt alle dominierenden Zyklen und skizziert daraus das wahrscheinlichste Bild für den Börsenverlauf der nächsten Jahre. Gewinnen mit Börsenzyklen ist das ultimative Basiswerk zu einem bisher fast unbekannten Analyseansatz, der in den nächsten Jahren noch erheblich an Popularität gewinnen wird. Mehr lesen', 'book', '["thomas-muller"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Hb5oLXeEdba-', 'Die 24 Geheimnisse des George Soros', 'George Soros war bis zum Herbst 1992 nur wenigen außerhalb des Exklusivkreises der Hochfinanz ein Begriff. Das änderte sich schlagartig im September 1992: Er setzte darauf, daß Großbritannien aufgrund der immer flauer werdenden Wirtschaftslage zu einer Abwertung des britischen Pfundes gezwungen sein würde - und seine Spekulation ging auf. Als das Pfund am 15. September 1992 tatsächlich abgewertet wurde, verdiente Soros buchstäblich über Nacht eine Milliarde Dollar. - Ein Star war geboren. George Soros nimmt unbestritten den Rang des weltweit berühmtesten Investors ein. Kein anderer hat über einen so langen Zeitraum hinweg derart hervorragende Ergebnisse erzielt wie Soros. Einen besseren Lehrer als George Soros gibt es nicht. Seit 1969, dem Gründungsjahr seines Quantum-Fonds, hat Soros mit seinen Investitionen einen unglaublichen Rekord aufgestellt. Ein im Jahr 1969 in den Quantum-Fonds investierter Betrag von 1.000 Dollar wäre bei Wiederveranlagung der Dividenden bis zum Jah r 1995 auf 2,150.000 Dollar angewachsen. Dieses Buch gewährt einen Einblick in Soros'' Anlagestrategien. Viele dieser Denkansätze sind für den Kleinanleger ebenso anwendbar wie für den professionellen Investor. Zwar ist die Kenntnis der Geheimnisse hinter Soros'' Investitionserfolgen sicherlich keine Garantie dafür, daß der Leser über Nacht eine Milliarde Dollar verdienen wird. Doch kann er, indem er sich ein Bild von der Denk- und Arbeitsweise George Soros'' verschafft und seine Schlüsselstrategien gedanklich nachvollzieht, zu einem besseren Verständnis der komplexen Welt der Hochfinanz gelangen; er kann selbst ein gewisses Gespür dafür entwickeln, das Geschehen in den Finanzmärkten richtig zu interpretieren und daraus Gewinne zu erzielen. Mehr lesen', 'book', '["robert-slater"]', '["buch", "genre", "biography"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-AKs8bwhz5wpq', 'Sovereign Risk Analysis: A New Qualitative Hybrid Approach for Early Warning', 'Eine umfassende Untersuchung der Staatsrisikobewertung, die einen neuartigen qualitativen Hybridansatz zur Früherkennung vorstellt und darauf abzielt, Vorhersage und Steuerung in Finanz- und Wirtschaftsbereichen zu verbessern.', 'book', '[]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-nDA6FRrvO91s', 'Charisma', 'Ein Ratgeber von Nikolaus B. Enkelmann, erschienen im Jahr 2012, der das Konzept des Charismas beleuchtet und praktische Hinweise gibt, wie man persönliche Ausstrahlung und Überzeugungskraft entwickeln und stärken kann.', 'book', '["nikolaus-b-enkelmann"]', '["buch", "genre", "self-help"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-TyfsRx6-bL_9', 'Die Kunst des Krieges für Führungskräfte', 'Ein strategisches Wirtschaftsbuch, das die alte Weisheit aus Sun Tzus «Die Kunst des Krieges» in praktische Ratschläge für Führungskräfte und Manager überträgt und Einblicke in wirksame Entscheidungsfindung, Unternehmensführung und Wettbewerbsstrategien in der Geschäftswelt bietet.', 'book', '["donald-g-krause"]', '["buch", "genre", "business"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-HQqA2_9lzZih', 'Es war einmal ein Zebra, das liebte die Algebra', 'Die köstlichen, spannenden Ministorys, zu heiter berührenden Versen verdichtet, sprühen vor Lebensfreude. Marty nutzt dabei die Tiefe und Bedeutungsvariationen der Worte und bietet dem Leser so die Möglichkeit, in eine weitere Ebene einzutauchen. Wie ansonsten bei seiner Arbeit mit Düften, geht der Parfumeur hier auf die »Seele« der Worte ein. Ein Geschenk im besten Sinne des Wortes. Mehr lesen', 'book', '["markus-marty"]', '["buch", "genre", "children-s-literature"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ZSU3ip4wncWj', 'Rhetorik – Handbuch der Redekunst (Band 2)', 'Ein umfassendes Werk zur Kunst der Rhetorik: Dieser Band von Roman Hofmeister widmet sich fortgeschrittenen Techniken und Strategien für wirkungsvolles öffentliches Sprechen und bietet Einblicke in Überzeugungskunst, Publikumsansprache und die Gestaltung von Reden. Das 2020 erschienene Buch ist ein unverzichtbares Nachschlagewerk für alle, die ihre Ausdrucksfähigkeit in verschiedenen Bereichen verfeinern möchten.', 'book', '["roman-hofmeister"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-1B-T-NtWTJbF', 'Rhetorik – Handbuch der Redekunst (Band 1)', 'Umfassender Leitfaden zur Kunst der Rhetorik, der Einblicke in wirkungsvolles öffentliches Sprechen und überzeugende Kommunikationstechniken bietet.', 'book', '["roman-hofmeister"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-rk9xerhM7ofC', 'Die 222 wichtigsten Fragen zu Derivaten', 'Ob Optionen, Futures oder Swaps – die Welt der Derivate ist vielfältig und für Privatanleger nicht immer leicht zu durchschauen. Oft können einem auch Banken und Anlageberater nicht weiterhelfen. Volker Meinel, selbst Banker mit einem offenen Ohr für seine Kunden, kämpft gegen diesen Missstand an. Nun hat Meinel seine jahrelangen Erfahrungen in 222 Fragen und Antworten zusammengefasst. Der Leser erhält einen optimalen Überblick über die Märkte und ist in der Lage, selbst erfolgreich an den weltweiten Finanzmärkten zu bestehen. - Der Autor bringt seine Erfahrung aus unzähligen Leserbriefen, Telefonaten und Messegesprächen ein - Ein weiteres Highlight aus der Reihe »Die 222 wichtigsten Fragen zu …« - Umfassende Einblicke in die Welt der Derivate - Durch das Frage-Antwort-Schema übersichtlich gegliedert Mehr lesen', 'book', '["volker-meinel"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6r6T20vq5oOS', 'Forex Conquered', 'Lobeshymnen auf FOREX CONQUERED
«In diesem erstaunlichen Buch deckt John alles ab. Von Handelssystemen über Geldmanagement bis hin zu Emotionen erklärt er verständlich, wie man dem kompliziertesten Finanzmarkt der Welt beständig Gewinne entlockt. John packt mehr neue, innovative Informationen in dieses Buch, als ich je zuvor in einem Handelsbuch gesehen habe.»
— Rob Booker, unabhängiger Devisenhändler
«John Person gehört zu den wenigen seltenen Talenten, die auf einzigartige Weise dazu befähigt sind, Händlern den Prozess des erfolgreichen Handels näherzubringen. Angesichts der zunehmenden Herausforderungen der heutigen Märkte hat John das Wesentliche herausgearbeitet und die dringend benötigten Werkzeuge des Devisenhandels in den Vordergrund gestellt. Diese klar strukturierte und gut organisierte Publikation ist ein bedeutender Schritt nach vorn, um Händlern einen Vorsprung zu verschaffen. Ich empfehle Forex Conquered wärmstens als wertvolles Handbuch für aufstrebende wie erfahrene Händler gleichermaßen.»
— Sandy Jadeja, Chefmarktanalyst und Redakteur, London Stock Exchange, London, England
«Forex Conquered ist ein gewagter Titel, doch dieses Buch liefert tatsächlich die Werkzeuge, die für einen erfolgreichen Devisenhandel benötigt werden. Kein Füllmaterial, nur die Weisheit eines Handelsveteranen, dem ich stets Respekt entgegengebracht und den ich stets verfolgt habe.»
— Michael Kahn, Redakteur, Quick Takes Pro market letter und Kolumnist, Barron''s Online
«Dies ist eine wunderbare, tiefgehende Einführung in die technische Analyse und umsichtige Geldmanagement-Richtlinien im Devisenmarkt.»
— Blake Morrow, Präsident, 4XMadeEasy
«Forex Conquered ist ein bedeutender Beitrag zur wachsenden Zahl von Büchern über den Devisenhandel. John Person bietet einen professionellen Blick auf den Devisenhandel, den Leser als Leitfaden für funktionierende Strategien und Taktiken nutzen können. Der Umfang des Buches geht über den Devisenhandel hinaus und umfasst wesentliche Aspekte des Termin- und Optionshandels. Es sollte gelesen – und dann erneut gelesen werden!»
— Abe Cofnas, Präsident, Learn4x.com
Hinweis: CD-ROM/DVD und anderes ergänzendes Material sind nicht Bestandteil der E-Book-Datei.', 'book', '["john-l-person"]', '["buch", "genre", "finance"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-8uo8rUuYgdhc', 'Der Schwarze Schwan', 'Die Weltbestseller des großen Zufallsforschers Ein “Schwarzer Schwan” ist ein Ereignis, auf das drei Dinge zutreffen: Es ist erstens ein Ausreißer – es liegt außerhalb der regulären Erwartungen, nichts in der Vergangenheit weist darauf hin. Es hat zweitens enorme Auswirkungen. Drittens bringt uns die menschliche Natur dazu, im Nachhinein Erklärungen für sein Eintreten zu konstruieren, um es erklärbar und vorhersagbar zu machen. In diesem bahnbrechenden Buch, das mittlerweile weltweit zum Klassiker geworden ist, entwickelt Taleb seine einflussreiche Denkfigur und Maxime für die ungewisse Realität, in der wir leben und handeln. Talebs Weltbestseller – „Der Schwarze Schwan: Die Macht höchst unwahrscheinlicher Ereignisse“ und „Der Schwarze Schwan: Konsequenzen aus der Krise“ – in einem Band und eingeleitet mit einem neuen Essay des Autors »Eines der zwölf einflussreichsten Bücher seit dem Zweiten Weltkrieg.« (Sunday Times) »›Der Schwarze Schwan‹ hat meine Sicht auf die Welt verändert.« (Daniel Kahneman, Nobelpreisträger) Der Weltbestseller: übersetzt in 33 Sprachen mit über 3 Millionen verkauften Exemplaren »Taleb zerpflückt mit großer Lust und einem guten Schuss Polemik unseren offenbar unerschütterlichen Glauben an die Vorhersehbarkeit von Ereignissen.« (SWR)', 'book', '["nassim-nicholas-taleb"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-0XjBem6mtHxK', 'Zeitmanagement mit Outlook', 'Ein umfassender Leitfaden zur Nutzung von Microsoft Outlook für effektives Zeitmanagement, verfasst von Schwert, Wagner und Obermayr. Dieses Sachbuch bietet Strategien und Tipps zur Steigerung der Produktivität und zur Organisation von Aufgaben mithilfe der Funktionen von Outlook.', 'book', '["schwert", "wagner", "obermayr"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-MfS9FyVvUd9f', 'Fighter Wing', 'Zum ersten Mal ein Einblick von innen in einen Kampfverband der Air Force – die Flugzeuge, die Technologie und die Menschen … mit Tom Clancy als Ihrem Führer. Tom Clancys frühere Erkundungen der amerikanischen Streitkräfte, Submarine und Armored Cav, enthüllten exklusive, nie zuvor veröffentlichte Informationen über die Menschen und die Technologie, die unsere Nation schützen. Nun begibt sich der gefeierte Autor von Clear and Present Danger und Debt of Honor mit der Elite der U.S. Air Force auf Höhenflug: dem Fighter Wing. Mit seinem mitreißenden Stil und seinem untrüglichen Blick fürs Detail fängt Clancy den Rausch des Starts, die Dramatik des Luftkampfes und die unablässigen Gefahren ein, denen unsere Kampfpiloten jeden Tag ihres Lebens ausgesetzt sind … und zeigt den Lesern, was es wirklich bedeutet, zur absoluten Elite zu gehören. Fighter Wing enthält: Detaillierte Analysen der führenden Kampfflugzeuge der Air Force, darunter den F-15 Eagle – Exklusive Fotografien, Illustrationen und Diagramme – Einen Einblick von innen in die Menschen hinter den Flugzeugen und Waffen – Kampfstrategien und Ausbildungsmethoden der U.S. Air Force', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-auoumYaNtDDw', 'Das Echo aller Furcht', 'Der Kalte Krieg scheint Vergangenheit, die Weltmächte verhandeln im Zeichen der Kooperation und setzen auf eine friedliche Zukunft. Doch hinter den Kulissen tickt eine gefährliche Zeitbombe, und ein seltsamer Bombenfund genügt, um einen weltumspannenden tödlichen Konflikt zu entfachen. Jack Ryan, Amerikas Geheimdienstmann für Top-Secret-Fälle, muss einen nahezu aussichtslosen Kampf gegen die Zeit gewinnen ...', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-fujtRVEV0NDu', 'Rainbow Six', 'Ein actionreicher Techno-Thriller über eine multinationale Eliteeinheit zur Terrorismusbekämpfung namens Rainbow, die unter der Führung von John Clark mit modernster Technologie und packenden Taktikoperationen verschiedene globale Bedrohungen bekämpft.', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-v22xVeqgfmdQ', 'Im Auge des Tigers', 'Die neue Form des internationalen Terrorismus fordert eine neue Generation von Jägern heraus: Es kommt die Zeit für Jack Ryan, Jr. und seinesgleichen. Ein Mann namens Mohammed sitzt in einem Wiener Kaffeehaus und schlägt einem Kolumbianer ein Geschäft vor: Mohammed hat ein starkes Netzwerk aus Agenten und Sympathisanten in ganz Europa und im Mittleren Osten, und der Kolumbianer ein ähnlich starkes Netzwerk im Drogenhandel Amerikas. Warum sollten sie nicht eine Allianz bilden? Das Potential für Profit wäre riesengroß – und das Potential für Zerstörung unvorstellbar.', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-LpzIOoT90DCE', 'Der Kardinal im Kreml', 'Von einem geheimen Ort in der Nähe der afghanischen Grenze aus haben Russen erstmals mit einem Laserstrahl einen US-Spionagesatelliten "geblendet". Ein Fall für Jack Ryan. «Ein Autor, der nicht in Science-fiction abdriftet, sondern realistische Ausgangssituationen spannend zum Roman verdichtet.» DER SPIEGEL', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-T9Z8XM8Gd0qC', 'Im Sturm', 'Das Attentat arabischer Fundamentalisten auf eines der wichtigsten Ölfelder Sibiriens bringt die GUS in einen fatalen Zugzwang. Um den Zusammenbruch ihrer maroden Wirtschaft zu verhindern, erzwingt Moskau sich Zugang zum Persischen Golf und schreckt auch vor einem Schlag gegen die NATO nicht zurück ...', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-5MjlkjYcDpo6', 'Der Schattenkrieg', 'Als kolumbianische Drogenbosse drei hochrangige US-Amerikaner töten, ist für den Geheimdienstmann Jack Ryan der Punkt erreicht, an dem er zurückschlagen muss. Er stellt eine Truppe kampferprobter Männer zusammen und führt sie in einen Schattenkrieg, in dem die üblichen Regeln nicht gelten.', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Vgbq-K_Y1G-N', 'Gnadenlos', 'John Kelly, ehemaliger US-Marine und Spezialist für riskante Missionen, erhält den Auftrag, amerikanische Geiseln aus Nordvietnam herauszuholen - eine beinahe aussichtslose Mission, zumal Kelly sich gerade durch einen privaten Rachefeldzug in Lebensgefahr gebracht hat. Ein Wettlauf gegen die Zeit beginnt, und der geringste Fehler könnte sein letzter sein ...', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Wst-0OfzmhAb', 'Befehl von oben', 'Jack Ryans schwerste Stunde Bei einem Flugzeugangriff auf das Kapitol kommt der amerikanische Präsident ums Leben. Spezialagent Jack Ryan, vor Kurzem zum Vizepräsidenten ernannt, muss von einem Tag auf den anderen die Amtsgeschäfte übernehmen. Derweil nutzen Amerikas Feinde ihre Chance: China und Taiwan stehen kurz vor einem Krieg, und der Iran plant, amerikanische Großstädte mit einem tödlichen Virus zu verseuchen ...', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-2__5JtUXjJ_D', 'Ehrenschuld', 'Jack Ryans härtester Einsatz Außenpolitisch stehen die USA kurz vor der Alarmstufe Rot. Man holt Jack Ryan als neuen Sicherheitsberater des Präsidenten an die vorderste Front. Doch bevor er loslegt, muss Ryan zuerst noch eine Ehrenschuld begleichen. Ein Politthriller der Sonderklasse! Mehr lesen', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-EbX3iNmGXb2U', 'Im Zeichen des Drachen', 'Ein packender Thriller vor dem Hintergrund internationaler Spionage und Intrigen. »Im Zeichen des Drachen« erzählt eine vielschichtige Geschichte über Machtkämpfe und geheime Operationen. Als die Spannungen zunehmen, müssen sich die Protagonisten in einer Welt voller Gefahr und Täuschung behaupten, in der Loyalitäten auf die Probe gestellt werden und nichts so ist, wie es scheint.', 'book', '["marc-olden"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book--X1sZeJKiOPm', 'Gegen alle Feinde', 'Internationale Intrigen, explosive Action – der neue große Tom Clancy Seit Jahren tobt der Konflikt im Mittleren Osten. Nun sieht es so aus, dass sich der Kriegsschauplatz verlagert hat. Die Taliban bedienen sich für ihre Machenschaften eines mexikanischen Drogenkartells und tragen den Kampf ins Heimatland des Erzfeindes – in die Vereinigten Staaten von Amerika. Tom Clancy, der Meister des internationalen Politthrillers, stellt uns seinen neuen Helden vor: Ex-Navy-SEAL Max Moore. Und der steht allein – gegen alle Feinde.', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6nC6RXBto_LU', 'Ziel erfasst', 'Ein hochspannender Thriller aus der Welt der Spionage und militärischen Taktik, in dem ausgeklügelte Verschwörungen und internationale Intrigen die Figuren zwingen, ein gefährliches Katz-und-Maus-Spiel zu bestehen.', 'book', '["tom-clancy"]', '["buch", "genre", "thriller"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-M366WVN8yNge', 'The European Dream', 'The European Dream von Jeremy Rifkin untersucht die sich wandelnde europäische Identität und stellt sie dem amerikanischen Traum gegenüber. Das Buch beleuchtet, wie Europas Vision Gemeinschaft, Nachhaltigkeit und Lebensqualität über individuellen Erfolg und materiellen Wohlstand stellt. Rifkin argumentiert, dass das europäische Modell einer globalisierten Welt eine zukunftsfähigere und gerechtere Perspektive bietet.', 'book', '["jeremy-rifkin"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-R4trCgIlkTfv', 'The Age of Access', 'Eine fesselnde Untersuchung darüber, wie der Wandel vom Eigentum zum Zugang Wirtschaft, Kultur und Alltag verändert – einer Welt, in der traditionelle Märkte zunehmend durch Netzwerke und Dienstleistungen ersetzt werden.', 'book', '["jeremy-rifkin"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-9KZtm5uDMO4Q', 'The Hydrogen Economy', 'Erkundet das Potenzial von Wasserstoff als nachhaltige Energiequelle und seine Rolle bei der Bewältigung globaler Energie- und Umweltherausforderungen.', 'book', '["jeremy-rifkin"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-KSL8EN6lEW-Q', 'The Biotech Century', 'Untersucht die tiefgreifenden Auswirkungen der Biotechnologie auf Gesellschaft, Wirtschaft und das menschliche Erleben, und analysiert sowohl die möglichen Vorteile als auch die ethischen Bedenken im Zusammenhang mit Gentechnik und biologischen Innovationen.', 'book', '["jeremy-rifkin"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-ai0JDC9kz4le', 'Das Quark und der Jaguar', 'Eine tiefgründige Erkundung der Komplexität der Natur, in der der Autor, ein Nobelpreisträger der Physik, den Verflechtungen einfacher und komplexer Phänomene nachspürt und Themen von der Teilchenphysik bis hin zu den Prozessen des menschlichen Bewusstseins und dem kunstvollen Gewebe des Universums nachgeht.', 'book', '["murray-gell-mann"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dl-tJXLrboMK', 'Einsteins Universum', 'Eine umfassende Erkundung von Einsteins Theorien, die in die Konzepte der Relativitätstheorie und deren Einfluss auf unser Verständnis des Universums eintaucht und einem breiten Publikum auf verständliche Weise nähergebracht wird.', 'book', '["nigel-calder"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-UWsoKaP8FZ_c', 'Kitsch ist Geschmackssache', 'Untersucht die subjektive Natur von Geschmack und Kitsch und beleuchtet die kulturellen, gesellschaftlichen und persönlichen Faktoren, die die Wahrnehmung ästhetischer Werte beeinflussen.', 'book', '["anja-weber"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-eBeYLxrTwmfJ', 'Der Traum von der Einheit des Universums', 'Eine umfassende Erkundung der Suche nach einer vereinheitlichten Theorie der Grundkräfte, die auf die Geschichte, die Herausforderungen und die wissenschaftlichen Meilensteine der Physik zurückblickt.', 'book', '["steven-weinberg"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-X3FOviQbQ2qy', 'Der grosse Entwurf', 'Warum existieren wir? – Neue Antworten auf die letzten fragen des Seins «Um das Universum auf fundamentalster Ebene zu verstehen, müssen wir nicht nur wissen, wie sich das Universum verhält, sondern auch, warum. Warum gibt es etwas und nicht einfach nichts? Warum existieren wir? Warum dieses besondere System von Gesetzen und nicht irgendein anderes? Das ist die letztgültige Frage nach dem Leben, dem Universum und dem ganzen Rest. Wir werden versuchen, sie in diesem Buch zu beantworten.» Stephen Hawking Mehr lesen', 'book', '["stephen-hawking", "leonard-mlodinow"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-pmrwOETwDPnn', 'Das Universum in der Nussschale', 'Über das surreale Wunder der modernen Raumzeit-Forschung Wie kam es, dass in einer bestimmten Phase der kosmischen Entwicklung Milliarden Sterne »angingen«, wie tickt das Uhrwerk, das sie dazu veranlaßte? Warum glüht der Himmel nicht, obwohl doch das ganze Universum glüht - oder stimmt das gar nicht? Warum bewegt sich das Universum von uns fort? Warum haben Raum und Zeit einen Anfang und sind nicht ewig? Warum ist die Welt nicht fest umrissen und endgültig? Warum sind wir eigentlich hier und nicht woanders? Gibt es im All andere Wesen, und wenn ja, wer sind sie, und wo sind sie? Die Suche nach der Formel, die das Universum erklärt, nach der »Theorie für alles« ist der heilige Gral der Physik. Stephen Hawking behandelt in ›Das Universum in der Nussschale‹ verschiedene Vorschläge dafür, wie zum Beispiel die String-Theorie und Super-Gravitation. Er zeigt, dass nicht jeder Raum, sondern auch jede Zeit eine Form annimmt. Er pokert mit Newton und Einstein, befasst sich mit der Frage, ob Zeitreisen möglich sind, sowie mit anderen kühnen Spekulationen und bietet einen einzigartigen Einblick in die Welt der modernen Astrophysik und Kosmologie. Taschenbuchausgabe auf der Grundlage der erweiterten Neuausgabe. Mit zahlreichen Abbildungen. Mehr lesen', 'book', '["stephen-hawking"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-HnzOuE694oGA', 'Wirtschaftsfreiheit und begrenzte Staatsverantwortung', 'Das Werk macht die Leserinnen und Leser mit den zentralen Elementen der schweizerischen Wirtschaftsverfassung vertraut und zeigt auf, wie der Gesetzgeber das Wirtschaftsverwaltungsrecht auf der Grundlage der Vorentscheide, Zielvorgaben und Aufträge des Verfassungsgebers ausgestaltet hat. Seit der dritten Auflage ist einerseits die neue Bundesverfassung in Kraft getreten, andererseits haben zahlreiche Bereiche des Wirtschaftsverwaltungsrechts umfassende Änderungen erfahren, die in der Neuauflage berücksichtigt wurden. Zugleich werden exemplarisch Hinweise auf Bezüge zum Wirtschaftsvölkerrecht gegeben. Das Buch ist trotz gewachsenem Umfang nach wie vor als Lehrbuch konzipiert. Wiederum wurden den einzelnen Paragrafen Ausgangsfragen vorangestellt, die mithilfe der Lektüre beantwortet werden können. "Übungsfälle" im Anschluss an einzelne Kapitel und "Lesepläne" animieren zur Vertiefung. Der Text und die Hinweise auf Judikatur und Gesetzgebung entsprechen dem Stand vom Mai 2006. Mehr lesen', 'book', '["klaus-a-vallender", "jens-lehne", "peter-hettich"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-Lxhlrzmq9PfO', 'Genetik in Cartoons', 'Eine humorvolle und lehrreiche Erkundung der Genetik – Larry Gonick und Mark Wheelis nutzen anschauliche Illustrationen und geistreiche Kommentare, um komplexe genetische Zusammenhänge auf unterhaltsame Weise zu vermitteln.', 'book', '["larry-gonick", "mark-wheelis"]', '["buch", "genre", "science"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-GAXhU10xJi0-', 'Asterix – Gesamtausgabe, Band 15', 'In dieser edlen, in Kunstleder gebundenen Gesamtausgabe kommen die Asterix-Abenteuer "Die Tochter des Vercingetorix", "Asterix und der Greif" und der brandneue Band "Die weiße Iris" zum Abdruck, sowie als besondere Zugabe der Sonderband "Der Goldene Hinkelstein". Komplettiert wird diese Ausgabe mit vielen Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experten Horst Berner. Mit diesem Band wird die Kunstleder-Gesamtausgabe beendet. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dD8moanDvduC', 'Asterix – Gesamtausgabe, Band 14', 'Inzwischen liegen bereits drei Abenteuer aus der Feder der Uderzo-Nachfolger Ferri und Conrad vor. In dieser edlen, in Kunstleder gebundenen Gesamtausgabe kommen die Asterix-Abenteuer "Der Papyrus des Cäsar" und "Asterix in Italien" zum Abdruck. Sowie als besondere Zugabe das Filmalbum zum Kinofilm "Asterix erobert Rom". Dazu gibt es viele Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experten Horst Berner. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-qAeCHMkgVvlV', 'Asterix – Gesamtausgabe, Band 13', 'Ein Jahr nach Erscheinen des sensationellen Erfolgs-Albums "Asterix bei den Pikten" erscheint das Schotten-Abenteuer unserer gallischen Helden auch in der Asterix-Gesamtausgabe. In edles Kunstleder gebunden enthält dieser Band außerdem die Skizzen des neuen Asterix-Zeichners Didier Conrad sowie das 2009 erschienen Album "Asterix und Obelix feiern Geburtstag". Dazu gibt es viele Hintergrundinformationen zur Entstehungsgeschichte der Abenteuer aus der Feder des Asterix-Experte Horst Berner. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo", "jean-yves-ferri", "didier-conrad"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-jmf10yuvIDs8', 'Asterix – Gesamtausgabe, Band 12', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Band 12 enthält mit "Asterix plaudert aus der Schule" eine Sammlung von Kurzgeschichten, die Uderzo und Goscinny ab 1966 zusätzlich zu den langen Abenteuern anfertigten. Hier erlaubten sie sich einige gestalterische und inhaltliche Freiheiten. Wer also Idefix in einer Sprechrolle sehen will oder wie die Autoren selbst einen Obelix-Doppelgänger treffen, bekommt hier die besondere Gelegenheit! Besonders ist auch der Besuch der Außerirdischen im gallischen Dorf in "Gallien in Gefahr". Die Skizzen zu diesem Album runden diesen Band der Gesamtausgabe ab. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xkSMYYrKT3qK', 'Asterix – Gesamtausgabe, Band 11', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In "Asterix und Maestria" finden die Gallier ihr Meisterin, in "Obelix auf Kreuzfahrt" finden sie das sagenumwobene Atlantis und in "Asterix und Latraviata" erliegen sie weiblichen Reizen. Zusätzlich zu den Geschichte von Albert Uderzo enthält auch dieser Band der Asterix Gesamtausgabe einen unmfangreichen redaktionellen Teil. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-mUp8I_aYmrZc', 'Asterix – Gesamtausgabe, Band 10', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In "Asterix im Morgenland" schickt Albert Uderzo den kleinen Gallier in den Orient. Zusätzlich zur Geschichte kommen auch die von Uderzo angefertigten Skizzen zum Abdruck, die einen Einblick in die Entstehung eines Comicabenteuers geben. Zudem enthält der Band mit "Wie Obelix als kleines Kind in den Zaubertrank geplumpst ist" eine Erzählung, die René Goscinny schon 1965 schrieb und von Uderzo nach dessen Tod mit herrlichen großformatigen Bildern illustriert wurde. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-SwIsBM75fayl', 'Asterix – Gesamtausgabe, Band 9', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Nach dem Tode René Goscinnys übernahm Zeichner Albert Uderzo auch die Rolle des Szenaristen. In seinem ersten alleinigen Werk "Der große Graben" erzählt er "Romeo und Julia" auf Gallier-Art. Dann schickt er Asterix und Obelix auf "Die Odyssee" in den nahen Osten. In "Der Sohn des Asterix" verhilft er dem überzeugten Junggesellen schließlich zu unerwarteten Vaterfreunden, als ein Findelkind vor seiner Haustür liegt… Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-eSgKQhWjw32U', 'Asterix – Gesamtausgabe, Band 8', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Dieser Band enthält die Reise der Gallier nach Amerika in "Die große Überfahrt", Obelix als Geschäftsmann im Hinkelstein-Business in "Obelix GmbH & Co. KG" sowie "Asterix bei den Belgiern", das letzte Abenteuer, an dem der 1977 verstorbene Texter René Goscinny mitwirkte. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-JTUjGHtjP1wt', 'Asterix – Gesamtausgabe, Band 7', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In Band 7 sorgt "Der Seher" im Dorf für Unruhe, denn die abergläubischen Bewohner glauben seine Vorhersagen – nur Asterix behält den Durchblick. In "Asterix auf Korsika" begeben sich unsere Freunde auf eine Reise auf die Mittelmeerinsel, deren Bewohner selbst für Asterix-Verhältnisse reichlich skurril sind. Und "Das Geschenk Cäsars" sorgt dafür, dass Majestix zum Wahlkampf um das Häuptlingsamt herausgefordert wird… Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-btPNMnQoOSAd', 'Asterix – Gesamtausgabe, Band 6', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In diesem Band: Bei den Schweizern treffen Asterix und Obelix auf Kuckucksuhren, Banken und die heilende Kraft des Edelweiß. In "Die Trabantenstadt" will Cäsar die Zukunft in die Antike bringen, indem er eine moderne Römersiedlung rings um das gallische Dorf bauen lässt. Und schließlich geht Häuptling Majestix eine Wette ein, er könne "Die Lorbeeren des Cäsar" beschaffen. Ausbaden dürfen diese vollmundige Ankündigung natürlich Asterix und Obelix… Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6AnG_8qIYOlH', 'Asterix – Gesamtausgabe, Band 5', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Dieser Band enthält die Alben "Asterix und der Kupferkessel", in dem der Gallier seine ganz persönliche Finanzkrise lösen muss, sowie "Asterix in Spanien", in dem er sich ins Land von Flamenco und Toreros aufmacht. Und im dritten Abenteuer versucht ein Zwietracht säender Römer im gallischen Dorf einen "Streit um Asterix" vom Zaun zu brechen. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-kkk1HBojmskY', 'Asterix – Gesamtausgabe, Band 4', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In diesem Band mischen Asterix und Obelix die römische Armee auf, planen einen Triumphzug und starten bei Olympia als Favoriten – dank Zaubertrank-Doping! Mit "Asterix als Legionär", "Asterix und der Arvenerschild" und "Asterix bei den Olympischen Spielen" enthält dieser Band drei der beliebtesten Abenteuer der Reihe. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-TuoSvF9I02nC', 'Asterix – Gesamtausgabe, Band 3', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Band 3 enthält drei legendäre Abenteuer: Majestix muss sich dem "Kampf der Häuptlinge" stellen, Asterix macht sich auf zu den Briten, die, nur weil die Römer einfallen, noch lange nicht ihre Teestunde absagen, und schließlich greifen die furchtlosen Normannen das gallische Dorf an. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-2hh--Og3q9fv', 'Asterix – Gesamtausgabe, Band 2', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. In den klassischen Abenteuern dieses Bandes gehen Asterix und Obelix auf Reisen: erst kämpfen sie als Gladiatoren in Rom für die Freiheit des entführten Troubadix, dann absolvieren sie eine antike Tour de France durch ganz Gallien und im fernen Ägypten treffen sie auf Königin Kleopatra. Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-5OHLK-KDZ9Ki', 'Asterix – Gesamtausgabe, Band 1', 'Neben der regulären Asterix-Albenreihe liegt auch die Gesamtausgabe in überarbeiteter Form vor. Alle Alben wurden sorgfältig neu koloriert und gelettert, auch die Vorworte des Asterix-Experten Horst Berner aktualisiert und auf den neuesten Stand gebracht. Allein die bewährte Umschlagsgestaltung der erfolgreichen Reihe ändert sich nicht. Ein Muss nicht nur für Sammler, sondern für jeden Comicfreund. Der erste Band der Reihe enthält "Asterix der Gallier", in dem unser Held 1959 sein Debüt gab, sowie die Abenteuer "Die goldene Sichel" und "Asterix und die Goten". Mit diesen Frühwerken legten Goscinny und Uderzo die Grundsteine für eine der erfolgreichsten Comicserien aller Zeiten! Mehr lesen', 'book', '["rene-goscinny", "albert-uderzo"]', '["buch", "genre", "comics"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-O6WqE3XTpgJJ', 'Der Wüstenkrieg in Afrika', 'Eine umfassende Darstellung des nordafrikanischen Konflikts im Zweiten Weltkrieg, die wichtige Schlachten, Strategien und militärische Führungspersönlichkeiten beleuchtet und durch detaillierte Analysen sowie historische Fotografien ergänzt wird. Dieses 1984 erschienene Werk von Janusz Piekalkiewicz bietet eine eingehende Untersuchung der Kriegshandlungen in den Wüstenlandschaften Afrikas.', 'book', '["janusz-piekalkiewicz"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-dJWYij-GbnTv', 'Seekrieg', 'Eine umfassende Darstellung der Seekriegsführung im Zweiten Weltkrieg, die Strategien, Schlachten und die Auswirkungen maritimer Auseinandersetzungen detailliert beschreibt und durch unterstützendes Bildmaterial sowie Augenzeugenberichte ergänzt wird.', 'book', '["janusz-piekalkiewicz"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-6Dr0HH2evyuI', 'Invasion', 'Eine historische Betrachtung der Strategien, Taktiken und Ereignisse bedeutender militärischer Invasionen, die die Vielschichtigkeit und Folgen dieser Operationen im Verlauf der Geschichte darlegt. Das 1974 von Janusz Piekalkiewicz veröffentlichte Werk bietet Einblicke in die Militärgeschichte mit dem Schwerpunkt auf sachlicher Berichterstattung und Analyse.', 'book', '["janusz-piekalkiewicz"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-gQNMtwcO74vz', 'Luftkrieg', 'Eine umfassende Untersuchung der Luftkriegsführung im Zweiten Weltkrieg, die Strategien, bedeutende Schlachten und technische Entwicklungen detailliert beschreibt. Das Buch verbindet historische Analyse mit Augenzeugenberichten und vermittelt ein lebendiges Bild vom Einfluss der Luftmacht auf den Ausgang des Krieges.', 'book', '["janusz-piekalkiewicz"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-oKpgBrrX81Zm', 'Der Präzisions-Luftkrieg gegen Land und Leute', 'Eine umfassende Analyse der Auswirkungen und Strategien des Präzisions-Luftkriegs auf die Zivilbevölkerung und Landschaften, unter Betrachtung sowohl historischer als auch moderner Zusammenhänge.', 'book', '["raimund-muller"]', '["buch", "genre", "non-fiction"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-e7olJ1w1qCSW', 'Der Zweite Weltkrieg', 'Die Neufassung im bewährten Format beleuchtet die Griechische Geschichte vor dem Hellenismus (8. Jh. ‒ 320 v.Chr) in neuartiger Weise: als Teil eines weiträumigen und verflochtenen Geschehens im Mittelmeerraum und am Rand von Großreichen; dabei spielen Mobilität, Migration und Krieg eine zentrale Rolle. Einen weiteren Schwerpunkt bilden die Lust der Griechen an der Politik sowie ihre Kreativität auf diesem Feld. Dabei genießen regionale und lokale Eigenheiten besondere Aufmerksamkeit. Als Alleinstellungsmerkmal bietet der Band einen umfangreichen, mit der gegliederten Bibliographie eng verzahnten Forschungsüberblick. Dieser stellt die Geschichte der Hellenen als Problem vor und orientiert Studierende, aber auch Fachleute benachbarter Disziplinen gründlich und mit weitem Blick über die Kategorien, Konsense und Kontroversen.', 'book', '["r-oldenbourg"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-xNLuudOROR2L', 'Der Erste Weltkrieg', 'Umfassende historische Darstellung des Ersten Weltkriegs mit detaillierter Schilderung wichtiger Schlachten, Strategien und politischer Einflüsse, unterstützt durch Fotografien und Berichte aus erster Hand.', 'book', '["janusz-piekalkiewicz"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
INSERT OR REPLACE INTO notes (slug, title, body, note_type, related_people, related_topics, source_journal_id, created_at) VALUES ('book-67IhUMr0ENuB', 'Flugzeugbewaffnung', 'Eine Erkundung der Entwicklung und Technik der Flugzeugbewaffnung, die den Werdegang der in der Luftfahrt eingesetzten Waffen und Systeme nachzeichnet – mit Einblicken in historische Meilensteine und technische Fortschritte vom angesehenen Luftfahrtautor Bill Gunston.', 'book', '["bill-gunston"]', '["buch", "genre", "history"]', NULL, '2026-05-11 23:09:48');
COMMIT;
